import { GaugeProvider, GaugeReading, GaugeHistory, GaugeSite, isValidReadingValue } from './provider';
import { formatStateCode } from '../utils/formatting';
import { fetchWithTimeout, DEFAULT_HEADERS } from '../utils/timeout';

function reformatReadings(readingsArr: any[]) {
    for (let i = 0; i < readingsArr.length; i++) {
        const reading = readingsArr[i];
        const date = new Date(reading.dateTime);
        reading.dateTime = date.getTime();

        if (isNaN(reading.dateTime)) {
            // Defensive fall-back for parsing issues
            continue;
        }

        if (reading.cms !== undefined) {
            const val = parseFloat(reading.cms);
            if (!isNaN(val) && val !== -999 && isValidReadingValue(val, "cms")) {
                reading.cms = val;
            } else {
                delete reading.cms;
            }
        }

        if (reading.m !== undefined) {
            const val = parseFloat(reading.m);
            if (!isNaN(val) && val !== -999 && isValidReadingValue(val, "m")) {
                reading.m = val;
            } else {
                delete reading.m;
            }
        }
    }
    readingsArr.sort((a, b) => a.dateTime - b.dateTime);
}

export function processCanadaCSV(text: string, startTs: number, endTs: number): Record<string, GaugeHistory> {
    const lines = text.split('\n');
    if (lines.length < 2) return {};

    const headers = lines[0].split(',').map(h => h.replace(/["\r]/g, '').trim());
    const idIdx = headers.indexOf('ID') !== -1 ? headers.indexOf('ID') : 0;
    const dateIdx = headers.indexOf('Date');
    const levelIdx = headers.indexOf("Water Level / Niveau d'eau (m)");
    const cmsIdx = headers.indexOf("Discharge / Débit (cms)");

    if (dateIdx === -1) return {}; 

    const gaugeReadingsBySite: Record<string, any[]> = {};

    for (let i = 1; i < lines.length; i++) {
        const row = lines[i].split(',').map(c => c.replace(/["\r]/g, '').trim());
        if (row.length < headers.length - 1) continue;

        const id = row[idIdx];
        if (!id) continue;

        if (!gaugeReadingsBySite[id]) gaugeReadingsBySite[id] = [];

        gaugeReadingsBySite[id].push({
            dateTime: row[dateIdx],
            m: levelIdx !== -1 ? row[levelIdx] : undefined,
            cms: cmsIdx !== -1 ? row[cmsIdx] : undefined
        });
    }

    const outputGauges: Record<string, GaugeHistory> = {};

    for (const gaugeID in gaugeReadingsBySite) {
        const results = gaugeReadingsBySite[gaugeID];
        reformatReadings(results);

        const trimmed = results.filter((r: any) => {
            if (isNaN(r.dateTime) || r.dateTime < startTs || r.dateTime > endTs) return false;
            // Keep if it has at least one data property
            const keys = Object.keys(r);
            return keys.some(k => k !== 'dateTime' && k !== 'isForecast');
        });

        if (trimmed.length > 0) {
            const hasCms = trimmed.some(r => r.cms !== undefined);
            outputGauges[gaugeID] = {
                id: gaugeID,
                name: `Canada Gauge ${gaugeID}`,
                readings: trimmed,
                units: hasCms ? "cms" : "m",
            };
        }
    }

    return outputGauges;
}

const ALL_PROVINCES = ["AB","BC","MB","NB","NL","NS","NT","NU","ON","PE","QC","SK","YT"];

const PREFIX_TO_PROVINCES: Record<string, string[]> = {
    "01": ["NB", "NS", "PE"],
    "02": ["QC", "ON", "NL"],
    "03": ["NL"],
    "04": ["ON", "MB"],
    "05": ["AB", "SK", "MB", "ON"],
    "06": ["MB", "SK", "AB", "NT", "NU"],
    "07": ["BC", "AB", "SK", "NT"],
    "08": ["BC", "YT"],
    "09": ["BC", "YT"],
    "10": ["NT", "NU", "BC", "YT"],
    "11": ["SK", "AB"]
};

function getProvincesForSite(siteID: string): string[] {
    const provPrefix = siteID.substring(0, 2).toUpperCase();
    if (ALL_PROVINCES.includes(provPrefix)) return [provPrefix];
    return PREFIX_TO_PROVINCES[provPrefix] || ALL_PROVINCES;
}

async function fetchCanadianProvince(province: string, startTs: number, endTs: number): Promise<Record<string, GaugeHistory>> {
    const url = `https://dd.weather.gc.ca/today/hydrometric/csv/${province}/hourly/${province}_hourly_hydrometric.csv`;
    try {
        const res = await fetchWithTimeout(url, {
            headers: {
                ...DEFAULT_HEADERS,
                'Accept': 'text/csv, application/csv'
            }
        }, 90000);
        if (!res.ok) return {};
        const text = await res.text();
        return processCanadaCSV(text, startTs, endTs);
    } catch {
        return {};
    }
}

async function fetchIndividualCanadaGauge(stationID: string, province: string, startTs: number, endTs: number): Promise<GaugeHistory | null> {
    const url = `https://dd.weather.gc.ca/today/hydrometric/csv/${province}/hourly/${province}_${stationID}_hourly_hydrometric.csv`;
    try {
        const res = await fetchWithTimeout(url, {
            headers: {
                ...DEFAULT_HEADERS,
                'Accept': 'text/csv, application/csv'
            }
        }, 60000);
        if (!res.ok) return null;
        const text = await res.text();
        const data = processCanadaCSV(text, startTs, endTs);
        return data[stationID] || null;
    } catch {
        return null;
    }
}

export const canadaProvider: GaugeProvider = {
    id: "EC", 
    preferredUnits: 'metric',
    capabilities: {
        hasForecast: false,
        hasSiteListing: true
    },

    async getLatest(siteCodes: string[]): Promise<Record<string, GaugeReading>> {
        const results: Record<string, GaugeReading> = {};
        const startTs = Date.now() - (1000 * 60 * 60 * 6); // 6 hours
        const endTs = Date.now() + 1000 * 60 * 60 * 24; // buffer

        // If a small number of sites, fetch individually
        if (siteCodes.length <= 10) {
            const fetches = siteCodes.flatMap(site => {
                const provs = getProvincesForSite(site);
                return provs.map(p => fetchIndividualCanadaGauge(site, p, startTs, endTs));
            });
            const arr = await Promise.all(fetches);
            arr.forEach(hist => {
                if (hist && hist.readings.length > 0) {
                    results[hist.id] = hist.readings[hist.readings.length - 1];
                }
            });
            return results;
        }

        const provincesToFetch = new Set<string>();
        siteCodes.forEach(code => {
             const provs = getProvincesForSite(code);
             provs.forEach(p => provincesToFetch.add(p));
        });

        const fetches = Array.from(provincesToFetch).map(p => fetchCanadianProvince(p, startTs, endTs));
        const arr = await Promise.all(fetches);

        for (const provData of arr) {
            for (const siteCode of siteCodes) {
                if (provData[siteCode] && provData[siteCode].readings.length > 0) {
                    const rdgs = provData[siteCode].readings;
                    results[siteCode] = rdgs[rdgs.length - 1]; // latest
                }
            }
        }
        return results;
    },

    async getHistory(siteCodes: string[], startTs: number, endTs?: number, _includeForecast?: boolean): Promise<Record<string, GaugeHistory>> {
        const maxTime = endTs ?? Date.now();
        const results: Record<string, GaugeHistory> = {};

        // If a small number of sites, fetch individually
        if (siteCodes.length <= 5) {
            const fetches = siteCodes.flatMap(site => {
                const provs = getProvincesForSite(site);
                return provs.map(p => fetchIndividualCanadaGauge(site, p, startTs, maxTime));
            });
            const arr = await Promise.all(fetches);
            arr.forEach(hist => {
                if (hist) {
                    results[hist.id] = hist;
                }
            });
            return results;
        }

        const provincesToFetch = new Set<string>();
        siteCodes.forEach(code => {
             const provs = getProvincesForSite(code);
             provs.forEach(p => provincesToFetch.add(p));
        });

        const fetches = Array.from(provincesToFetch).map(p => fetchCanadianProvince(p, startTs, maxTime));
        const arr = await Promise.all(fetches);

        for (const provData of arr) {
            for (const siteCode of siteCodes) {
                if (provData[siteCode]) {
                    results[siteCode] = provData[siteCode];
                }
            }
        }
        return results;
    },

    async getSiteListing(siteCodes: string[]): Promise<GaugeSite[]> {
        const results: GaugeSite[] = [];
        const CONCURRENCY_LIMIT = 5;
        let index = 0;

        const worker = async () => {
             while (index < siteCodes.length) {
                 const site = siteCodes[index++];
                 try {
                     const url = `https://api.weather.gc.ca/collections/hydrometric-stations/items?STATION_NUMBER=${site}&f=json`;
                     const res = await fetchWithTimeout(url, {
                         headers: DEFAULT_HEADERS
                     }, 60000);
                     if (res.ok) {
                         const data: any = await res.json();
                         if (data.features && data.features.length > 0) {
                             const feat = data.features[0];
                             results.push({
                                 id: site,
                                 name: feat.properties?.STATION_NAME || site,
                                 lon: feat.geometry?.coordinates?.[0] || 0,
                                 lat: feat.geometry?.coordinates?.[1] || 0,
                                 state: feat.properties?.PROVINCE_TERRITORY_CODE || getProvincesForSite(site)[0]
                             });
                         }
                     }
                 } catch (_e) {
                    console.warn(`Canada history fetch failed for ${site}`, _e);
                }
             }
        };
        await Promise.all(Array(CONCURRENCY_LIMIT).fill(0).map(() => worker()));
        return results;
    },

    async getFullSiteListing(): Promise<GaugeSite[]> {
        console.log("Canada Provider: Fetching full site metadata...");
        const results: GaugeSite[] = [];
        try {
            const res = await fetchWithTimeout("https://wateroffice.ec.gc.ca/services/map_data", {
                headers: DEFAULT_HEADERS
            }, 90000);
            if (!res.ok) throw new Error(`Canada WaterOffice API Error: ${res.status}`);

            const data = await res.json() as any[];
            if (!Array.isArray(data)) {
                console.error("Canada Provider: Expected array from map_data, got", typeof data);
                return [];
            }

            for (const site of data) {
                // Use station_id as the primary identifier
                const id = site.station_id || site.station_number;
                if (!id) continue;

                const lat = parseFloat(site.latitude || site.lat);
                const lon = parseFloat(site.longitude || site.lon || site.long);

                if (!isNaN(lat) && !isNaN(lon)) {
                    results.push({
                        id,
                        name: site.station_name || site.name || `Canada Gauge ${id}`,
                        lat,
                        lon,
                        state: formatStateCode(site.province, "Canada")
                    });
                }
            }
        } catch (e) {
            console.error("Canada Provider: Failed to fetch site listing", e);
        }
        return results;
    }
};

import { GaugeProvider, GaugeReading, GaugeHistory, GaugeSite, isValidReadingValue } from './provider';
import { formatStateCode, formatGaugeName } from '../utils/formatting';
import { fetchWithTimeout, DEFAULT_HEADERS } from '../utils/timeout';

/**
 * Hub'Eau France (Hydrométrie API) Gauge Data Service
 */
export const franceProvider: GaugeProvider = {
    id: "france",
    preferredUnits: 'metric',
    capabilities: {
        hasForecast: false,
        hasSiteListing: true
    },

    async getLatest(siteCodes: string[]): Promise<Record<string, GaugeReading>> {
        const results: Record<string, GaugeReading> = {};

        // If we want the latest for all or many, it's efficient to fetch the last hour
        // For a specific small list, we could use code_entite, but the "all last hour"
        // approach is robust for the background sync.

        const now = new Date();
        const oneHourAgo = new Date(now.getTime() - 60 * 60 * 1000);
        const isoDate = oneHourAgo.toISOString().split('.')[0] + 'Z';

        const fetchMetric = async (metric: 'H' | 'Q') => {
            const baseUrl = "https://hubeau.eaufrance.fr/api/v2/hydrometrie/observations_tr";
            let url = `${baseUrl}?size=20000&date_obs_min=${isoDate}&grandeur_hydro=${metric}`;

            // If specific site codes are provided, and the list is small enough, we can filter by them
            // However, Hub'Eau observation query for many IDs is slow/limited.
            // For discovery/sync, siteCodes is often empty or a massive list.
            const siteSet = new Set(siteCodes);
            const filterByIds = siteCodes.length > 0 && siteCodes.length < 50;

            if (filterByIds) {
                url += `&code_entite=${siteCodes.join(',')}`;
            }

            try {
                const res = await fetchWithTimeout(url, { headers: DEFAULT_HEADERS }, 90000); // Increased to 90s for large observations fetch
                if (!res.ok) return;

                const data: any = await res.json();
                const items = data.data || [];

                for (const item of items) {
                    const id = item.code_station;
                    if (!id) continue;
                    if (siteCodes.length > 0 && !siteSet.has(id)) continue;

                    const ts = new Date(item.date_obs).getTime();
                    const val = Number(item.resultat_obs);

                    if (!results[id]) {
                        results[id] = { dateTime: ts };
                    }

                    // Hub'Eau sorts desc by default, so first one we see is the latest
                    if (ts > results[id].dateTime) {
                        results[id].dateTime = ts;
                    }

                    if (metric === 'H') {
                        if (isValidReadingValue(val / 1000, "m")) {
                            results[id].m = val / 1000; // mm to m
                        }
                    } else {
                        if (isValidReadingValue(val / 1000, "cms")) {
                            results[id].cms = val / 1000; // L/s to m3/s
                        }
                    }
                }
            } catch (e) {
                console.error(`France getLatest ${metric} failed:`, e);
            }
        };

        await Promise.all([fetchMetric('H'), fetchMetric('Q')]);
        return results;
    },

    async getHistory(siteCodes: string[], startTs: number, endTs?: number, _includeForecast?: boolean): Promise<Record<string, GaugeHistory>> {
        const results: Record<string, GaugeHistory> = {};
        const maxTime = endTs ?? Date.now();
        const isoStart = new Date(startTs).toISOString().split('.')[0] + 'Z';

        const CONCURRENCY_LIMIT = 3;
        let index = 0;

        const worker = async () => {
            while (index < siteCodes.length) {
                const id = siteCodes[index++];
                const readingsMap: Record<number, GaugeReading> = {};

                const fetchMetricHistory = async (metric: 'H' | 'Q') => {
                    const url = `https://hubeau.eaufrance.fr/api/v2/hydrometrie/observations_tr?code_entite=${id}&date_obs_min=${isoStart}&grandeur_hydro=${metric}&size=5000&sort=asc`;
                    try {
                        const res = await fetchWithTimeout(url, { headers: DEFAULT_HEADERS }, 60000); // 60s timeout per station history
                        if (!res.ok) return;
                        const data: any = await res.json();
                        const items = data.data || [];

                        for (const item of items) {
                            const ts = new Date(item.date_obs).getTime();
                            const val = Number(item.resultat_obs);
                            if (ts > maxTime) continue;

                            if (!readingsMap[ts]) {
                                readingsMap[ts] = { dateTime: ts };
                            }

                            if (metric === 'H') {
                                if (isValidReadingValue(val / 1000, "m")) {
                                    readingsMap[ts].m = val / 1000;
                                }
                            } else {
                                if (isValidReadingValue(val / 1000, "cms")) {
                                    readingsMap[ts].cms = val / 1000;
                                }
                            }
                        }
                    } catch (e) {
                        console.warn(`France history fetch failed for ${id} ${metric}`, e);
                    }
                };

                await Promise.all([fetchMetricHistory('H'), fetchMetricHistory('Q')]);

                const readings = Object.values(readingsMap).toSorted((a, b) => a.dateTime - b.dateTime);
                if (readings.length > 0) {
                    const formatted = formatGaugeName(id); // Name will be refined if we have site mapping
                    results[id] = {
                        id,
                        name: formatted.name,
                        readings,
                        units: "m"
                    };
                }
            }
        };

        await Promise.all(Array(CONCURRENCY_LIMIT).fill(0).map(() => worker()));
        return results;
    },

    async getSiteListing(siteCodes: string[]): Promise<GaugeSite[]> {
        // Normally used for individual history lookup metadata
        // For France, we can fetch metadata for a specific station
        const results: GaugeSite[] = [];
        const CONCURRENCY_LIMIT = 5;
        let index = 0;

        const worker = async () => {
            while (index < siteCodes.length) {
                const id = siteCodes[index++];
                const url = `https://hubeau.eaufrance.fr/api/v2/hydrometrie/referentiel/stations?code_station=${id}`;
                try {
                    const res = await fetchWithTimeout(url, { headers: DEFAULT_HEADERS }, 60000); // 60s timeout per station info
                    if (!res.ok) continue;
                    const data: any = await res.json();
                    const item = data.data?.[0];
                    if (item && item.latitude && item.longitude) {
                        const formatted = formatGaugeName(item.libelle_station || id);
                        results.push({
                            id,
                            name: formatted.section ? `${formatted.name} ${formatted.section}` : formatted.name,
                            lat: item.latitude,
                            lon: item.longitude,
                            state: formatStateCode(item.code_departement, "france")
                        });
                    }
                } catch (e) {
                    console.warn(`France site metadata fetch failed for ${id}`, e);
                }
            }
        };

        await Promise.all(Array(CONCURRENCY_LIMIT).fill(0).map(() => worker()));
        return results;
    },

    async getFullSiteListing(): Promise<GaugeSite[]> {
        console.log("France Provider: Fetching full site listing...");
        const results: GaugeSite[] = [];
        let nextUrl: string | null = "https://hubeau.eaufrance.fr/api/v2/hydrometrie/referentiel/stations?en_service=true&size=1000";
        let pageCount = 0;
        const MAX_PAGES = 50; // Safety cap to prevent infinite loops

        try {
            while (nextUrl && pageCount < MAX_PAGES) {
                pageCount++;
                const res = await fetchWithTimeout(nextUrl, { headers: DEFAULT_HEADERS }, 90000); // 90s timeout per directory page
                if (!res.ok) break;
                const data: any = await res.json();
                const items = data.data || [];

                for (const item of items) {
                    // Filter for stations that actually have real-time capabilities to avoid junk
                    if (!item.grandeur_h_reelle && !item.grandeur_q_reelle) continue;

                    if (item.code_station && item.latitude && item.longitude) {
                        const rawName = item.libelle_station || item.libelle_site || `France Station ${item.code_station}`;
                        const formatted = formatGaugeName(rawName);
                        results.push({
                            id: item.code_station,
                            name: formatted.section ? `${formatted.name} ${formatted.section}` : formatted.name,
                            lat: item.latitude,
                            lon: item.longitude,
                            state: formatStateCode(item.code_departement, "france")
                        });
                    }
                }
                nextUrl = data.next || null;
            }
            if (pageCount >= MAX_PAGES) {
                console.warn("France Provider: Reached MAX_PAGES limit during full site listing.");
            }
        } catch (e) {
            console.error("France Provider: Full site listing failed", e);
            throw e;
        }

        return results;
    }
};

import { GaugeProvider, GaugeReading, GaugeHistory, GaugeSite, isValidReadingValue } from './provider';
import { formatStateCode, formatGaugeName } from '../utils/formatting';
import { fetchWithTimeout, DEFAULT_HEADERS } from '../utils/timeout';

/**
 * Ireland (WaterLevel.ie / OPW) Gauge Data Service
 */

export const irelandProvider: GaugeProvider = {
    id: "ireland",
    preferredUnits: 'metric',
    capabilities: {
        hasForecast: false,
        hasSiteListing: true
    },

    async getLatest(siteCodes: string[]): Promise<Record<string, GaugeReading>> {
        const results: Record<string, GaugeReading> = {};
        const url = "https://waterlevel.ie/geojson/latest/";

        try {
            const res = await fetchWithTimeout(url, { headers: DEFAULT_HEADERS }, 90000); // Increased to 90s for Ireland latest readings
            if (!res.ok) return results;

            const data: any = await res.json();
            const features = data.features || [];

            const siteSet = new Set(siteCodes);

            for (const f of features) {
                const props = f.properties || {};
                const id = props.station_ref;
                if (!id || !siteSet.has(id)) continue;

                if (props.value !== undefined && isValidReadingValue(props.value, "m")) {
                    results[id] = {
                        dateTime: new Date(props.datetime).getTime(),
                        m: Number(props.value)
                    };
                }
            }
        } catch (e: unknown) {
            console.error("Ireland getLatest Failed:", e);
        }
        return results;
    },

    async getHistory(siteCodes: string[], startTs: number, endTs?: number, _includeForecast?: boolean): Promise<Record<string, GaugeHistory>> {
        const maxTime = endTs ?? Date.now();
        const durationMs = maxTime - startTs;
        const period = durationMs > 1000 * 60 * 60 * 24 * 7 ? "month" : "week";
        const results: Record<string, GaugeHistory> = {};

        const CONCURRENCY_LIMIT = 3;
        let index = 0;

        const worker = async () => {
            while (index < siteCodes.length) {
                const stationId = siteCodes[index++];
                // We'll primarily fetch gauge 0001 (water level)
                const url = `https://waterlevel.ie/data/${period}/${stationId}_0001.csv`;

                try {
                    const res = await fetchWithTimeout(url, { headers: { ...DEFAULT_HEADERS, 'Accept': 'text/csv' } }, 60000); // Increased to 60s timeout per Ireland history CSV
                    if (!res.ok) continue;

                    const text = await res.text();
                    const lines = text.split('\n');
                    if (lines.length < 2) continue;

                    const readings: GaugeReading[] = [];

                    // OPW CSV format: datetime,value (without headers in some cases, or has generic headers)
                    for (let i = 0; i < lines.length; i++) {
                        const line = lines[i].trim();
                        if (!line || line.startsWith("#") || line.startsWith("datetime")) continue;

                        const [dtStr, valStr] = line.split(',');
                        const ts = new Date(dtStr).getTime();
                        if (isNaN(ts) || ts < startTs || ts > maxTime) continue;

                        if (isValidReadingValue(valStr, "m")) {
                            readings.push({
                                dateTime: ts,
                                m: Number(valStr)
                            });
                        }
                    }

                    const formatted = formatGaugeName(stationId);
                    results[stationId] = {
                        id: stationId,
                        name: formatted.name,
                        section: formatted.section,
                        readings: readings.toSorted((a, b) => a.dateTime - b.dateTime),
                        units: "m"
                    };
                } catch (e) {
                    console.warn(`Ireland history fetch failed for ${stationId}`, e);
                }
            }
        };

        await Promise.all(Array(CONCURRENCY_LIMIT).fill(0).map(() => worker()));
        return results;
    },

    async getSiteListing(siteCodes: string[]): Promise<GaugeSite[]> {
        const fullListing = await this.getFullSiteListing!();
        const siteSet = new Set(siteCodes);
        return fullListing.filter(s => siteSet.has(s.id));
    },

    async getFullSiteListing(): Promise<GaugeSite[]> {
        console.log("Ireland Provider: Fetching full site listing...");
        const url = "https://waterlevel.ie/geojson/latest/";
        const results: GaugeSite[] = [];

        try {
            const res = await fetchWithTimeout(url, { headers: DEFAULT_HEADERS }, 90000); // Increased to 90s timeout for Ireland site listing
            if (!res.ok) throw new Error(`Ireland OPW API Error: ${res.status}`);

            const data: any = await res.json();
            const features = data.features || [];

            for (const f of features) {
                const props = f.properties || {};
                const id = props.station_ref;
                const coords = f.geometry?.coordinates || [0, 0];

                if (id && props.value !== undefined) {
                    const rawName = props.station_name || `Ireland Station ${id}`;
                    const formatted = formatGaugeName(rawName);
                    results.push({
                        id: id,
                        name: formatted.section ? `${formatted.name} ${formatted.section}` : formatted.name,
                        lat: coords[1],
                        lon: coords[0],
                        state: formatStateCode(props.region || props.county, "Ireland")
                    });
                }
            }
        } catch (e: unknown) {
            console.error("Ireland Provider: Full site listing failed", e);
            throw e;
        }

        return results;
    }
};

import { GaugeProvider, GaugeReading, GaugeHistory, GaugeSite, isValidReadingValue } from './provider';
import { formatStateCode, formatGaugeName } from '../utils/formatting';
import { fetchWithTimeout, DEFAULT_HEADERS } from '../utils/timeout';

// Internal helper for mapping NWPS data arrays to GaugeReadings (exported for testing)
export function parseNWSeries(data: any, observations: any[], minTime: number, maxTime: number, isForecast: boolean): Map<number, GaugeReading> {
    const primaryIsStage = data.primaryUnits === "ft";
    const secondaryIsStage = data.secondaryUnits === "ft";
    const primaryIsFlow = data.primaryUnits === "kcfs" || data.primaryUnits === "cfs";
    const secondaryIsFlow = data.secondaryUnits === "kcfs" || data.secondaryUnits === "cfs";

    const readingMap = new Map<number, GaugeReading>();

    observations.forEach((obs: any) => {
        const rawTime = new Date(obs.validTime).getTime();
        if (rawTime < minTime || rawTime > maxTime) return;

        // Align timestamps like USGS to Nearest 5 minutes
        const snappedTime = Math.round(rawTime / 300000) * 300000;
        if (!readingMap.has(snappedTime)) {
            readingMap.set(snappedTime, { dateTime: snappedTime, ...(isForecast && { isForecast: true }) });
        }

        const reading = readingMap.get(snappedTime)!;

        if (primaryIsStage && obs.primary != null && isValidReadingValue(obs.primary, "ft")) {
            reading.ft = Number(obs.primary);
        } else if (secondaryIsStage && obs.secondary != null && isValidReadingValue(obs.secondary, "ft")) {
            reading.ft = Number(obs.secondary);
        }

        let flowVal = null;
        if (primaryIsFlow && obs.primary != null && obs.primary !== "") flowVal = obs.primary;
        else if (secondaryIsFlow && obs.secondary != null && obs.secondary !== "") flowVal = obs.secondary;

        if (flowVal != null) {
            let finalFlow = Number(flowVal);
            if (data.primaryUnits === "kcfs" || data.secondaryUnits === "kcfs") {
                finalFlow *= 1000;
            }

            if (isValidReadingValue(finalFlow, "cfs")) {
                reading.cfs = finalFlow;
            }
        }
    });

    return readingMap;
}

export const nwsProvider: GaugeProvider = {
    id: "NWS",
    preferredUnits: 'imperial',
    capabilities: {
        hasForecast: true,
        hasSiteListing: true
    },

    async getLatest(siteCodes: string[]): Promise<Record<string, GaugeReading>> {
        // Fetch 3 hours to ensure we get at least one recent reading
        const histories = await this.getHistory(siteCodes, Date.now() - 10800000, Date.now(), false);
        const results: Record<string, GaugeReading> = {};

        Object.entries(histories).forEach(([id, history]) => {
            if (history.readings.length > 0) {
                results[id] = history.readings[history.readings.length - 1];
            }
        });

        return results;
    },

    async getHistory(siteCodes: string[], startTs: number, endTs?: number, includeForecast?: boolean): Promise<Record<string, GaugeHistory>> {
        const maxTime = endTs ?? Date.now();
        const results: Record<string, GaugeHistory> = {};

        const CONCURRENCY_LIMIT = 5;
        let index = 0;

        const worker = async () => {
            while (index < siteCodes.length) {
                const site = siteCodes[index++];
                const url = `https://api.water.noaa.gov/nwps/v1/gauges/${site}/stageflow`;
                let attempts = 0;
                let success = false;
                while (!success && attempts <= 2) {
                    try {
                        const res = await fetchWithTimeout(url, { headers: DEFAULT_HEADERS }, 60000); // 60s timeout per NWS gauge
                        if (!res.ok) {
                            if (res.status === 404) break;
                            throw new Error(`NWPS HTTP Error: ${res.status}`);
                        }

                        const data: any = await res.json();

                        const readingMap = new Map<number, GaugeReading>();

                        // Parse Observed
                        if (data.observed?.data) {
                           const parsedObs = parseNWSeries(data.observed, data.observed.data, startTs, maxTime, false);
                           parsedObs.forEach((v, k) => readingMap.set(k, v));
                        }

                        // Parse Forecast
                        if (includeForecast && data.forecast?.data) {
                           const parsedFcst = parseNWSeries(data.forecast, data.forecast.data, startTs, maxTime, true);
                           parsedFcst.forEach((v, k) => {
                               // Overwrite or append forecast
                               readingMap.set(k, { ...readingMap.get(k), ...v, isForecast: true });
                           });
                        }

                        const timestamps = Array.from(readingMap.keys()).sort((a, b) => a - b);
                        const readings = timestamps
                            .map(ts => readingMap.get(ts)!)
                            .filter(r => {
                                const keys = Object.keys(r);
                                return keys.some(k => k !== 'dateTime' && k !== 'isForecast');
                            });

                        const formatted = formatGaugeName(site);
                        results[site] = {
                            id: site,
                            name: formatted.name,
                            section: formatted.section,
                            readings
                        };
                        success = true;
                    } catch (_e: unknown) {
                        attempts++;
                        if (attempts > 2) {
                            console.error(`NWPS Fetch failed for ${site}`, _e);
                        } else {
                            await new Promise(r => setTimeout(r, attempts * 2000));
                        }
                    }
                }
            }
        };

        await Promise.all(Array(CONCURRENCY_LIMIT).fill(0).map(() => worker()));
        return results;
    },

    async getSiteListing(siteCodes: string[]): Promise<GaugeSite[]> {
        const results: GaugeSite[] = [];
        const CONCURRENCY_LIMIT = 5;
        let index = 0;

        const worker = async () => {
             while (index < siteCodes.length) {
                 const site = siteCodes[index++];
                 try {
                     const res = await fetchWithTimeout(`https://api.water.noaa.gov/nwps/v1/gauges/${site}`, { headers: DEFAULT_HEADERS }, 60000);
                         if (res.ok) {
                             const data: any = await res.json();
                             if (data.latitude !== undefined && data.longitude !== undefined) {
                                 const formatted = formatGaugeName(data.name || site);
                                 results.push({
                                     id: site,
                                     name: formatted.section ? `${formatted.name} ${formatted.section}` : formatted.name,
                                     lat: data.latitude,
                                     lon: data.longitude
                                 });
                             }
                         }
                 } catch (_e) {
                     console.warn(`NWS site listing failed for ${site}`, _e);
                 }
             }
        };
         await Promise.all(Array(CONCURRENCY_LIMIT).fill(0).map(() => worker()));
         return results;
     },

     async getFullSiteListing(): Promise<GaugeSite[]> {
         console.log("NWS Provider: Fetching full site listing...");
         const url = "https://api.water.noaa.gov/nwps/v1/gauges";
         const results: GaugeSite[] = [];

         try {
             const res = await fetchWithTimeout(url, { headers: DEFAULT_HEADERS }, 90000); // 90s timeout for NWS full list
             if (!res.ok) throw new Error(`NWS NWPS API Error: ${res.status}`);

             const data: any = await res.json();
             const items = data.gauges || [];

             for (const item of items) {
                 if (item.identifier && item.latitude !== undefined && item.longitude !== undefined) {
                     const formatted = formatGaugeName(item.name || item.identifier);
                     results.push({
                         id: item.identifier,
                         name: formatted.section ? `${formatted.name} ${formatted.section}` : formatted.name,
                         lat: item.latitude,
                         lon: item.longitude,
                         state: formatStateCode(item.state?.abbreviation, "NWS")
                     });
                 }
             }
         } catch (e) {
             console.error("NWS Provider: Full site listing failed", e);
             throw e;
         }

         return results;
     }
 };

import { GaugeProvider, GaugeReading, GaugeHistory, GaugeSite, isValidReadingValue } from './provider';
import { formatStateCode, formatGaugeName } from '../utils/formatting';
