    const acronyms = new Set([
        'USGS', 'USA', 'TVA', 'NWS', 'GSM', 'UK', 'OPW', 'NWPS',
        'I', 'II', 'III', 'IV', 'V', 'VI', 'VII', 'VIII', 'IX', 'X'
