export default GlobalNavBar;

import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import type { RiverData } from "../types/River";
import { getSkillAbbreviation, getSkillFull } from "../utils/skillTranslations";
import { calculateColor } from "../utils/flowInfoCalculations";

import { useLists } from "../context/ListsContext";
import { useSettings } from "../context/SettingsContext";
import { useAuth } from "../context/AuthContext";
import { useModal } from "../context/ModalContext";
import { ListSelectModal } from "./ListSelectModal";

interface RiverItemProps {
  river: RiverData;
  index: number;
  isDarkMode?: boolean;
  isColorBlindMode?: boolean;
  initiallyExpanded?: boolean; // legacy prop, preserved for safety

}

function slugify(text: string) {
  if (!text) return '';
  const cleaned = text.toString().toLowerCase()
    .replace(/\s+/g, '-')
    .replace(/[^\w-]+/g, '');
  return cleaned.split('-').filter(Boolean).join('-');
}

export const RiverItem: React.FC<RiverItemProps> = ({
  river,
  index,
  isDarkMode = false,
  isColorBlindMode = false,

}) => {
  const navigate = useNavigate();
  const baseId = `b${index}`;

  const riverClass = river.class ? river.class.split("(").join("\u200b(") : "";
  const translatedSkill = getSkillFull(river.skill);
  const skillAbbr = getSkillAbbreviation(river.skill);

  const buttonClassNames = [
    "riverbutton",
    river.isGauge ? "riverbuttonGauge" : "",
    river.dam ? "riverbuttonDam" : "",
  ]
    .filter(Boolean)
    .join(" ");

  const bgColor = river.isReadingStale ? null : calculateColor(
    river.running ?? null,
    isDarkMode,
    isColorBlindMode,
  );

  const { myLists, addRiverToList, removeRiverFromList, toggleRiverInQuickList } = useLists();
  const { quickActionPref } = useSettings();
  const { user, setAuthModalOpen } = useAuth();
  const { confirm } = useModal();
  const [isModalOpen, setModalOpen] = useState(false);

  let targetListId: string | null = null;

  if (myLists.length === 1) {
    targetListId = myLists[0].id;
  } else if (quickActionPref.startsWith("list:")) {
    targetListId = quickActionPref.split(":")[1];
  } else if (quickActionPref === "favorites") {
    const favList = myLists.find(l => l.title === "Favorites");
    if (favList) targetListId = favList.id;
  }

  let isActive = false;
  let displayIcon = "☆";
  let displayColor = "inherit";

  if (targetListId) {
    const list = myLists.find(l => l.id === targetListId);
    if (list) {
      isActive = list.rivers.some(r => r.id === river.id);

      if (myLists.length === 1 || quickActionPref === "favorites") {
        displayIcon = isActive ? "★" : "☆";
      } else {
        displayIcon = isActive ? "✓" : "+";
      }
      displayColor = isActive ? "#ffd700" : "inherit";
    }
  }

  const handleActionClick = async (e: React.MouseEvent) => {
    e.stopPropagation();

    if (!user) {
        const shouldSignIn = await confirm("Please sign in to save favorites and sync them across your devices.", "Sign In Required");
        if (shouldSignIn) {
            setAuthModalOpen(true);
        }
        return;
    }

    try {
      if (targetListId) {
         if (isActive) {
            await removeRiverFromList(targetListId, river.id);
         } else {
            await addRiverToList(targetListId, river);
         }
      } else if (myLists.length === 0) {
         await toggleRiverInQuickList(river, "favorites");
      } else {
         setModalOpen(true);
      }
    } catch (e: any) {
      console.error("Failed to perform list action:", e);
      await confirm(e.message || "Failed to update your list. Please try again.", "Error Updating List");
    }
  };

  const handleCloseModal = () => setModalOpen(false);

  const handleNavigate = () => {
     let slug = slugify(river.name);
     if (river.section) slug += '-' + slugify(river.section);
     const prefix = river.isGauge ? '/gauge/' : '/river/';
     navigate(`${prefix}${river.id}/${slug}`);
  };

  const getFlowDisplay = () => {
    if ((river.flowInfo || typeof river.flow === "string") && !river.isReadingStale) {
      return (
        <span className="riverspan flowspan">
          {river.flowInfo || (typeof river.flow === "string" ? river.flow : "")}
        </span>
      );
    }
    if (river.dam) {
      return <span className="riverspan flowspan">Dam</span>;
    }
    return <span className="riverspan flowspan"></span>;
  };

  const getFavTitle = () => {
    if (quickActionPref.startsWith("list:")) {
      return isActive ? "Remove from List" : "Add to List";
    }
    if (quickActionPref === "ask" && myLists.length > 0) {
      return "Save River to Lists";
    }
    return isActive ? "Remove River from Lists" : "Add River to Lists";
  };


  return (
    <React.Fragment>
      <button
        id={`${baseId}1`}
        className={buttonClassNames}
        style={bgColor ? { backgroundColor: bgColor } : {}}
        onClick={handleNavigate}
      >
        <span className="riverspan">{river.name}</span>
        <span className="riverspan">{river.section}</span>

        {/* Skill Span */}
        <span
          className="riverspan skillspan tooltip"
          style={{ borderBottom: "none" }}
        >
          <div className="tooltip">
            {skillAbbr}
            <span className="tooltiptext">{translatedSkill}</span>
          </div>
        </span>

        {/* Class Span */}
        <span className="riverspan classspan">{(!riverClass || riverClass.trim().toLowerCase() === "unknown") ? "?" : riverClass}</span>


        {/* Flow Span */}
        {getFlowDisplay()}


        {/* State Span */}
        <span 
          className={`riverspan statespan ${river.states?.includes(',') ? "tooltip tooltip-bottom" : ""}`}
          style={river.states?.includes(',') ? { borderBottom: "none", cursor: "pointer" } : {}}
        >
          {river.states?.includes(',') ? `${river.states.split(',')[0].trim()}+` : (river.states || "")}
          {river.states?.includes(',') && (
             <span className="tooltiptext" style={{ fontWeight: "normal", fontSize: "0.95em", padding: "6px 10px" }}>
                 {river.states.split(',').map((s: string)=>s.trim()).join(', ')}
             </span>
          )}
        </span>

        {/* Favorite Span (Moved to Right) */}
        <span
          className="riverspan favspan"
          title={getFavTitle()}

          style={{
            color: displayColor,
            fontWeight: quickActionPref.startsWith("list:") ? "bold" : "normal",
            fontSize: quickActionPref.startsWith("list:") ? "1.3em" : "1.2em"
          }}
          onClick={handleActionClick}
        >
          {displayIcon}
        </span>

        {isModalOpen && (
           <ListSelectModal 
              isOpen={isModalOpen} 
              onClose={handleCloseModal} 
              riverId={river.id} 
           />
        )}
      </button>

    </React.Fragment>
  );
};

import React, { useState, useEffect } from "react";
import ReactDOM from "react-dom";
import type { AdvancedSearchQuery } from "../utils/SearchFilters";

interface ShareMapModalProps {
    isOpen: boolean;
    onClose: () => void;
    currentQuery: AdvancedSearchQuery;
    mapCenter: [number, number];
    mapZoom: number;
}

export const ShareMapModal: React.FC<ShareMapModalProps> = ({
    isOpen,
    onClose,
    currentQuery,
    mapCenter,
    mapZoom
}) => {
    const [shareFilters, setShareFilters] = useState(true);
    const [shareMapState, setShareMapState] = useState(true);
    const [linkType, setLinkType] = useState<"map" | "list">("map");
    const [pinCoordinates, setPinCoordinates] = useState(true);
    const [generatedUrl, setGeneratedUrl] = useState("");
    const [copied, setCopied] = useState(false);

    useEffect(() => {
        if (!isOpen) {
            setCopied(false);
            return;
        }

        const baseUrl = linkType === "map" 
            ? window.location.origin + window.location.pathname
            : window.location.origin + "/";

        const url = new URL(baseUrl);

        if (shareMapState && linkType === "map") {
            url.searchParams.set("lat", mapCenter[0].toFixed(5));
            url.searchParams.set("lng", mapCenter[1].toFixed(5));
            url.searchParams.set("zoom", mapZoom.toString());
        }

        if (shareFilters) {
            if (currentQuery.name) url.searchParams.set("name", currentQuery.name);
            if (currentQuery.section) url.searchParams.set("section", currentQuery.section);
            if (currentQuery.distanceMax) {
                url.searchParams.set("distanceMax", currentQuery.distanceMax.toString());

                let modeToShare = currentQuery.mapRadiusMode || "current";
                let latToShare = currentQuery.userLat;
                let lonToShare = currentQuery.userLon;

                if (pinCoordinates) {
                    if (modeToShare === "current") {
                        modeToShare = "custom";
                    } else if (modeToShare === "center") {
                        if (linkType === "list" || !shareMapState) {
                            modeToShare = "custom";
                            latToShare = mapCenter[0];
                            lonToShare = mapCenter[1];
                        }
                    }
                } else {
                    if (modeToShare === "current") {
                        latToShare = undefined;
                        lonToShare = undefined;
                    } else if (modeToShare === "center") {
                        if (linkType === "list") {
                            modeToShare = "current"; 
                            latToShare = undefined;
                            lonToShare = undefined;
                        } else {
                            latToShare = undefined;
                            lonToShare = undefined;
                        }
                    }
                }

                url.searchParams.set("radiusMode", modeToShare);
                if (latToShare !== undefined) url.searchParams.set("userLat", typeof latToShare === "number" ? latToShare.toFixed(5) : latToShare);
                if (lonToShare !== undefined) url.searchParams.set("userLon", typeof lonToShare === "number" ? lonToShare.toFixed(5) : lonToShare);
            }
            if (currentQuery.favoritesOnly) url.searchParams.set("favoritesOnly", "true");

            // Only add skill/flow if not default
            if (currentQuery.skillMin !== 1) url.searchParams.set("skillMin", currentQuery.skillMin!.toString());
            if (currentQuery.skillMax !== 8) url.searchParams.set("skillMax", currentQuery.skillMax!.toString());
            if (currentQuery.flowMin !== 0) url.searchParams.set("flowMin", currentQuery.flowMin!.toString());
            if (currentQuery.flowMax !== 4) url.searchParams.set("flowMax", currentQuery.flowMax!.toString());
        }

        setGeneratedUrl(url.toString());
    }, [isOpen, shareFilters, shareMapState, currentQuery, mapCenter, mapZoom, linkType, pinCoordinates]);

    if (!isOpen) return null;

    const handleCopy = async () => {
        try {
            await navigator.clipboard.writeText(generatedUrl);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        } catch (err) {
            console.error("Failed to copy", err);
        }
    };

    return ReactDOM.createPortal(
        <div
            style={{
                position: "fixed",
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                backgroundColor: "rgba(15, 23, 42, 0.75)",
                backdropFilter: "blur(8px)",
                zIndex: 9999,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                padding: "20px",
                animation: "fadeIn 0.2s ease-out",
            }}
            onClick={onClose}
        >
            <div
                style={{
                    width: "100%",
                    maxWidth: "500px",
                    backgroundColor: "var(--surface)",
                    borderRadius: "16px",
                    boxShadow: "0 20px 25px -5px rgba(0, 0, 0, 0.1)",
                    display: "flex",
                    flexDirection: "column",
                    position: "relative",
                    padding: "24px",
                }}
                onClick={(e) => e.stopPropagation()}
            >
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "20px" }}>
                    <h2 style={{ margin: 0, color: "var(--text)" }}>Share Map View</h2>
                    <button
                        onClick={onClose}
                        style={{
                            background: "none",
                            border: "none",
                            fontSize: "24px",
                            cursor: "pointer",
                            color: "var(--text-muted)",
                        }}
                    >
                        ✕
                    </button>
                </div>

                <div style={{ display: "flex", flexDirection: "column", gap: "15px", marginBottom: "20px" }}>
                    <div style={{ display: "flex", gap: "20px" }}>
                        <label style={{ display: "flex", alignItems: "center", gap: "5px", color: "var(--text)", cursor: "pointer" }}>
                            <input 
                                type="radio" 
                                name="linkType"
                                checked={linkType === "map"} 
                                onChange={() => setLinkType("map")} 
                                style={{ width: "16px", height: "16px", cursor: "pointer" }}
                            />
                            Link to Map View
                        </label>
                        <label style={{ display: "flex", alignItems: "center", gap: "5px", color: "var(--text)", cursor: "pointer" }}>
                            <input 
                                type="radio" 
                                name="linkType"
                                checked={linkType === "list"} 
                                onChange={() => setLinkType("list")} 
                                style={{ width: "16px", height: "16px", cursor: "pointer" }}
                            />
                            Link to List View
                        </label>
                    </div>

                    {linkType === "map" && (
                        <div style={{ display: "flex", flexDirection: "column" }}>
                            <label style={{ display: "flex", alignItems: "center", gap: "10px", color: "var(--text)", cursor: "pointer" }}>
                                <input 
                                    type="checkbox" 
                                    checked={shareMapState} 
                                    onChange={(e) => setShareMapState(e.target.checked)} 
                                    style={{ width: "20px", height: "20px", cursor: "pointer" }}
                                />
                                Share Map Zoom & Focus Location
                            </label>
                            <span style={{ fontSize: "0.8em", color: "var(--text-muted)", marginLeft: "30px", marginTop: "2px" }}>
                                Preserves the exact view of the map you're looking at right now so the recipient sees the same area.
                            </span>
                        </div>
                    )}
                    <div style={{ display: "flex", flexDirection: "column" }}>
                        <label style={{ display: "flex", alignItems: "center", gap: "10px", color: "var(--text)", cursor: "pointer" }}>
                            <input 
                                type="checkbox" 
                                checked={shareFilters} 
                                onChange={(e) => setShareFilters(e.target.checked)} 
                                style={{ width: "20px", height: "20px", cursor: "pointer" }}
                            />
                            Share Filters & Advanced Search Radius
                        </label>
                        <span style={{ fontSize: "0.8em", color: "var(--text-muted)", marginLeft: "30px", marginTop: "2px" }}>
                            Includes your current search filters (Class, Flow, Name, Distance Radius, etc) in the generated link.
                        </span>
                    </div>

                    {shareFilters && currentQuery.distanceMax !== undefined && (
                        <div style={{ display: "flex", flexDirection: "column", marginLeft: "24px" }}>
                            <label style={{ display: "flex", alignItems: "center", gap: "10px", color: "var(--text)", cursor: "pointer", fontSize: "0.9em" }}>
                                <input 
                                    type="checkbox" 
                                    checked={pinCoordinates} 
                                    onChange={(e) => setPinCoordinates(e.target.checked)} 
                                    style={{ width: "20px", height: "20px", cursor: "pointer" }}
                                />
                                Lock Radius Coordinates
                            </label>
                            <span style={{ fontSize: "0.8em", color: "var(--text-muted)", marginLeft: "30px", marginTop: "2px" }}>
                                If checked, the link will pin your exact coordinates for the radius origin. If unchecked, the radius will dynamically evaluate from the recipient's device location.
                            </span>
                        </div>
                    )}
                </div>

                <div style={{ display: "flex",flexDirection: "column", gap: "10px" }}>
                    <label style={{ fontSize: "0.85em", fontWeight: "bold", color: "var(--text-secondary)", textTransform: "uppercase" }}>Generated Link</label>
                    <div style={{ display: "flex", gap: "10px" }}>
                        <input 
                            type="text" 
                            disabled 
                            value={generatedUrl} 
                            style={{
                                flex: 1,
                                padding: "10px",
                                borderRadius: "8px",
                                border: "1px solid var(--border)",
                                backgroundColor: "var(--surface-hover)",
                                color: "var(--text)",
                                fontSize: "0.9em"
                            }}
                        />
                        <button 
                            onClick={handleCopy}
                            style={{
                                padding: "10px 16px",
                                borderRadius: "8px",
                                border: "none",
                                backgroundColor: copied ? "var(--success, #10b981)" : "var(--primary)",
                                color: "white",
                                fontWeight: "bold",
                                cursor: "pointer",
                                transition: "all 0.2s"
                            }}
                        >
                            {copied ? "Copied!" : "Copy"}
                        </button>
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
};

