                    <Popup 
                        position={[activePopupData.lat, activePopupData.lon]} 
                        eventHandlers={{
                            remove: () => setActivePopupData(null)
                        }}
                        offset={[0, -20]}
                    >
                        <div style={{ textAlign: "center", fontSize: "1.1em" }}>
                            <strong>{activePopupData.point?.name || (activePopupData.point?.type === "put-in" ? "Put-In" : "Take-Out")}</strong>
                            <br />
                            <a 
                                href={`https://www.google.com/maps/dir/?api=1&destination=${activePopupData.lat},${activePopupData.lon}`} 
                                target="_blank" 
                                rel="noreferrer"
                                style={{ display: "inline-block", marginTop: "8px", fontWeight: "bold" }}
                            >
                                Open in Google Maps
                            </a>
                        </div>
                    </Popup>
                )}



                {/* Local User Physical GPS Position Marker */}
                {location.latitude && location.longitude && (
                    <CircleMarker
                        center={[location.latitude, location.longitude]}
                        radius={7}
                        fillColor="#3b82f6"
                        fillOpacity={1.0}
                        color="#ffffff"
                        weight={2}
                    >
                        <Tooltip direction="top" offset={[0, -5]}>
                            <div style={{ textAlign: "center" }}>
                                <strong>Your Current Location</strong><br />
                                {location.latitude.toFixed(5)}, {location.longitude.toFixed(5)}
                            </div>
                        </Tooltip>
                    </CircleMarker>
                )}

                {/* Distance Radius Circle */}
                {searchQuery.distanceMax && (
                    <Circle 
                        center={(searchQuery.mapRadiusMode === "center" || !location.latitude || !location.longitude) ? mapCenter : [location.latitude, location.longitude]} 
                        radius={searchQuery.distanceMax * 1609.34} // Convert miles to meters
                        pathOptions={{ 
                            fillColor: 'var(--primary)', 
                            fillOpacity: 0.1, 
                            color: 'var(--primary)', 
                            weight: 2, 
                            dashArray: "4 4" 
                        }} 
                    />
                )}
            </MapContainer>

            {/* Universally Injected Selected River Sidebar */}
            {selectedRiver && (
                <div
                    className="river-details-sidebar"
                    style={{
                        position: "absolute",
                        top: 0,
                        right: 0,
                        bottom: 0,
                        width: "100%",
                        maxWidth: "450px",
                        backgroundColor: "var(--surface)",
                        zIndex: 2000,
                        boxShadow: "-4px 0 15px rgba(0,0,0,0.2)",
                        overflowY: "auto",
                        borderLeft: "1px solid var(--border)"
                    }}
                >
                    <div
                        style={{
                            padding: "20px",
                            paddingTop: isFullScreen ? "calc(20px + var(--safe-area-inset-top, env(safe-area-inset-top, 0px)))" : "20px",
                            position: "sticky",
                            top: 0,
                            backgroundColor: "var(--surface)",
                            borderBottom: "1px solid var(--border)",
                            zIndex: 10,
                            display: "flex",
                            justifyContent: "space-between",
                            alignItems: "center",
                        }}
                    >
                        <h2 style={{ margin: 0, color: "var(--text)" }}>
                            {selectedAccessPoint && selectedAccessPoint.name && (
                                <span style={{ display: "block", fontSize: "0.85em", color: "var(--primary)", marginBottom: "4px" }}>
                                    {(() => {
                                        if (selectedAccessPoint.type === 'put-in') return 'Put-In: ';
                                        if (selectedAccessPoint.type === 'take-out') return 'Take-Out: ';
                                        return 'Access: ';
                                    })()}
                                    {selectedAccessPoint.name}
                                </span>
                            )}

                            {selectedRiver.name}{" "}
                            {selectedRiver.section ? `(${selectedRiver.section})` : ""}
                        </h2>
                        <button
                            onClick={() => {
                                setSelectedRiver(null);
                                setSelectedAccessPoint(null);
                            }}
                            style={{
                                border: "none",
                                background: "transparent",
                                fontSize: "2em",
                                cursor: "pointer",
                                color: "var(--text-muted)",
                                lineHeight: 1,
                            }}
                        >
                            &times;
                        </button>
                    </div>

                    <div style={{ padding: "0 20px 20px 20px", color: "var(--text-secondary)" }}>
                            {selectedAccessPoint && selectedAccessPoint.lat && (
                                <div style={{ marginBottom: "15px" }}>
                                    <a 
                                        href={`https://www.google.com/maps/dir/?api=1&destination=${selectedAccessPoint.lat},${selectedAccessPoint.lon}`} 
                                        target="_blank" 
                                        rel="noreferrer"
                                        style={{ display: "inline-block", backgroundColor: "var(--primary)", color: "#fff", padding: "8px 12px", borderRadius: "8px", fontWeight: "bold", textDecoration: "none" }}
                                    >
                                        📍 Navigate in Google Maps
                                    </a>
                                </div>
                            )}

                            <RiverExpansion 
                                 key={selectedRiver.id}
                                 river={selectedRiver} 
                                 isMapOverlay={true} 
                            />
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useState, useMemo } from "react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  ReferenceLine,
} from "recharts";
import type { RiverData } from "../types/River";
import { useSettings } from "../context/SettingsContext";

interface Props {
  river: RiverData;
  dataGeneratedAt?: number | null;
}

const formatDate = (timestamp: number) => {
  const d = new Date(timestamp);
  return `${d.getHours()}:${d.getMinutes().toString().padStart(2, "0")} ${d.getMonth() + 1}/${d.getDate()}`;
};

const getUnit = (dataKey: string) => {
  if (dataKey === "cfs") return "cfs";
  if (dataKey === "cms") return "cms";
  if (dataKey === "feet" || dataKey === "ft") return "ft";
  if (dataKey === "m" || dataKey === "meters") return "m";
  if (dataKey === "temp") return "°F";
  return "in";
};

const CustomTooltip = ({ active, payload, label, isDarkMode, activeTab, flowKey, stageKey, volumeColor, stageColor, tempColor, precipColor }: any) => {
  if (active && payload && payload.length) {
    const rowData = payload[0].payload;
    const items: { name: string, value: any, color: string, dataKey: string }[] = [];

    if (activeTab === "flow") {
      const isForecastFlow = rowData[flowKey] == null && rowData[`${flowKey}Forecast`] != null;
      const isForecastStage = rowData[stageKey] == null && rowData[`${stageKey}Forecast`] != null;

      const flowVal = rowData[flowKey] ?? rowData[`${flowKey}Forecast`];
      const stageVal = rowData[stageKey] ?? rowData[`${stageKey}Forecast`];

      items.push({ 
        name: isForecastFlow ? "Forecasted Flow" : "Flow", 
        value: flowVal, 
        color: volumeColor, 
        dataKey: flowKey 
      });
      items.push({ 
        name: isForecastStage ? "Forecasted Stage" : "Stage", 
        value: stageVal, 
        color: stageColor, 
        dataKey: stageKey 
      });
    } else if (activeTab === "temp") {
      items.push({ 
        name: "Temperature", 
        value: rowData.temp, 
        color: tempColor, 
        dataKey: "temp" 
      });
    } else if (activeTab === "precip") {
      items.push({ 
        name: "Precipitation", 
        value: rowData.precip, 
        color: precipColor, 
        dataKey: "precip" 
      });
    }

    return (
      <div
        style={{
          backgroundColor: isDarkMode ? "rgba(15, 23, 42, 0.9)" : "rgba(255, 255, 255, 0.9)",
          color: isDarkMode ? "#f8fafc" : "#0f172a",
          padding: "10px",
          borderRadius: "4px",
          border: isDarkMode ? "1px solid #475569" : "1px solid #cbd5e1",
        }}
      >
        <p style={{ margin: "0 0 5px 0", fontSize: "1.35em", color: isDarkMode ? "#94a3b8" : "#475569" }}>
          {formatDate(label)}
        </p>
        {items.map((entry: any, index: number) => (
          <p
            key={`item-${index}`}
            style={{ 
                margin: 0, 
                color: entry.value != null ? entry.color : "var(--text-muted)", 
                fontWeight: "bold", 
                fontSize: "1.35em",
                opacity: entry.value != null ? 1 : 0.6
            }}
          >
            {entry.name}: {entry.value != null ? `${entry.value} ${getUnit(entry.dataKey)}` : "(No Reading)"}
          </p>
        ))}
      </div>
    );
  }
  return null;
};

export const USGSGraphs: React.FC<Props> = ({ river, dataGeneratedAt }) => {
  const [activeGaugeId, setActiveGaugeId] = useState<string | undefined>(
    river.gauges?.find((g: any) => g.isPrimary)?.id || river.gauges?.[0]?.id
  );
  const rawData = activeGaugeId && river.gaugeData ? river.gaugeData[activeGaugeId] || [] : [];

  const isGraphStale = useMemo(() => {
     if (rawData.length === 0) return false;
     let latestActualReading = null;
     for (let i = rawData.length - 1; i >= 0; i--) {
         const d = rawData[i];
         if (d.cfs != null || d.ft != null || d.cms != null || d.m != null) {
             latestActualReading = d;
             break;
         }
     }
     if (!latestActualReading) return false;

     // 2-hour relative staleness rule: Reading must be within 2 hours of the sync generation
     const syncTime = dataGeneratedAt || Date.now();
     return (syncTime - latestActualReading.dateTime) > 2 * 60 * 60 * 1000;
  }, [rawData, dataGeneratedAt]);

  const hasForecastData = useMemo(() => {
    return rawData.some((d: any) => d.cfsForecast != null || d.ftForecast != null || d.forecast === true);
  }, [rawData]);

  const [showForecast, setShowForecast] = useState<boolean>(true);

  const [timeRange, setTimeRange] = useState<number>(3);
  const data = useMemo(() => {
     if (rawData.length === 0) return [];

     // Find the latest actual reading to use as our "present time" anchor.
     // This prevents future forecasted points from shifting the historical window forward.
     let anchorTime = rawData[rawData.length - 1].dateTime;
     for (let i = rawData.length - 1; i >= 0; i--) {
       const d = rawData[i];
       if (d.cfs != null || d.ft != null || d.cms != null || d.m != null || d.temp != null || d.precip != null) {
         anchorTime = d.dateTime;
         break;
       }
     }

     const minTime = anchorTime - (timeRange * 24 * 60 * 60 * 1000);
     return rawData.filter(d => d.dateTime >= minTime && (showForecast || d.dateTime <= anchorTime));
  }, [rawData, timeRange, showForecast]);

  const { isDarkMode, isColorBlindMode } = useSettings();

  // Detect available datasets
  const hasFlow = data.some((d) => d.cfs != null || d.ft != null || d.cms != null || d.m != null || d.cfsForecast != null || d.ftForecast != null);
  const hasTemp = data.some((d) => d.temp != null);
  const hasPrecip = data.some((d) => d.precip != null);

  const flowKey = data.some((d) => d.cfs != null || d.cfsForecast != null) ? "cfs" : "cms";
  const stageKey = data.some((d) => d.ft != null || d.ftForecast != null) ? "ft" : "m";

  type TabType = "flow" | "temp" | "precip";
  let defaultTab: TabType = "precip";
  if (hasFlow) defaultTab = "flow";
  else if (hasTemp) defaultTab = "temp";

  const [userTab, setUserTab] = useState<TabType | "auto">("auto");
  const activeTab = userTab === "auto" ? defaultTab : userTab;

  const precipSummary = useMemo(() => {
    if (!hasPrecip || data.length === 0) return null;
    const startTime = data[data.length - 1].dateTime;
    let halfDay,
      fullDay,
      sum = 0;

    for (let i = data.length - 1; i >= 0; i--) {
      const pt = data[i];
      const currentTime = pt.dateTime;
      if (pt.precip) sum += pt.precip;

      if (
        halfDay === undefined &&
        startTime - currentTime >= 1000 * 60 * 60 * 12
      )
        halfDay = Math.round(sum * 1000) / 1000;
      if (
        fullDay === undefined &&
        startTime - currentTime >= 1000 * 60 * 60 * 24
      )
        fullDay = Math.round(sum * 1000) / 1000;
    }
    const finalSum = Math.round(sum * 1000) / 1000;
    if (fullDay !== undefined)
      return `Last 24 hours: ${fullDay}"   Last 12 hours: ${halfDay}"`;
    if (halfDay !== undefined)
      return `Last 12 hours: ${halfDay}"   Total: ${finalSum}"`;
    return `Total Precipitation: ${finalSum}"`;
  }, [data, hasPrecip]);

  const hasNoData = !data || data.length === 0 || (!hasFlow && !hasTemp && !hasPrecip);

  // Theme styling
  const volumeColor = isColorBlindMode ? "#ff8800" : "#00CCFF";
  let stageColor = "blue";
  if (isColorBlindMode) {
      stageColor = isDarkMode ? "#00CCFF" : "#7175ff";
  } else if (isDarkMode) {
      stageColor = "#7175ff";
  }

  const tempColor = isDarkMode ? "#00AAFF" : "red";
  const precipColor = "#0099FF";
  const axisColor = "var(--text-secondary)";

  const metricOptionsCount = (hasFlow ? 1 : 0) + (hasTemp ? 1 : 0) + (hasPrecip ? 1 : 0);

  const titleElement = (() => {
      const activeGauge = river.gauges?.find((g: any) => g.id === activeGaugeId);
      const name = activeGauge?.name || activeGaugeId;

      let link = undefined;
      if (activeGaugeId) {
        const parts = activeGaugeId.split(':');
        if (parts.length >= 2) {
            const type = parts[0].toLowerCase();
            const id = parts[1];
            if (type === 'usgs') link = `https://waterdata.usgs.gov/monitoring-location/${id}/#parameterCode=00060,00065,00010,00011,00045&period=P7D`;
            else if (type === 'canada') link = `https://wateroffice.ec.gc.ca/report/real_time_e.html?stn=${id}`;
            else if (type === 'nws') link = `https://water.noaa.gov/gauges/${id}`;
        }
      }

      if (link) {
        return <a href={link} target="_blank" rel="noopener noreferrer" style={{ fontWeight: "bold", color: "var(--text)", textDecoration: "none" }}>{name} <span style={{ fontSize: "0.8em" }}>↗</span></a>;
      }
      return <span style={{ fontWeight: "bold", color: "var(--text)" }}>{name}</span>;
  })();

  return (
    <div className="usgs-graphs-container" style={{ marginTop: "20px" }}>
      {/* Title (Centered on top if multiple gauges exist) */}
      {(!river.gauges || river.gauges.length > 1) && (
        <div style={{ textAlign: "center", marginBottom: "15px", fontSize: "1.25em" }}>
          {titleElement}
        </div>
      )}

      <div style={{ display: "flex", flexWrap: "wrap", gap: "10px", marginBottom: "15px", alignItems: "center" }}>
        {/* Gauge Dropdown (if multiple gauges exist), else inline Title */}
        {river.gauges && river.gauges.length > 1 ? (
          <select
            value={activeGaugeId}
            onChange={(e) => setActiveGaugeId(e.target.value)}
            style={{
              padding: "8px 12px",
              borderRadius: "8px",
              border: "1px solid var(--border)",
              backgroundColor: "var(--surface)",
              color: "var(--text)",
              cursor: "pointer",
              fontWeight: "bold",
              flexShrink: 1,
              maxWidth: "40vw",
              textOverflow: "ellipsis"
            }}
          >
            {river.gauges.map((g) => {
              const label = (() => {
                if (g.section) return g.section;
                if (g.name) return g.name;
                return g.id;
              })();
              return (
                <option key={g.id} value={g.id}>
                  {label} {g.isPrimary ? "(Primary)" : ""}
                </option>
              );
            })}
          </select>
        ) : (
          <div style={{ fontSize: "1.15em", flexShrink: 1, textOverflow: "ellipsis", whiteSpace: "nowrap", overflow: "hidden" }}>
             {titleElement}
          </div>
        )}

        <div style={{ display: "flex", flexWrap: "wrap", gap: "10px", flex: "1 1 auto", justifyContent: river.gauges && river.gauges.length > 1 ? "flex-end" : "space-between" }}>
            {/* Metric Switch */}
            {!hasNoData && metricOptionsCount > 1 && (
                <div style={{ display: "flex", borderRadius: "8px", overflow: "hidden", border: "1px solid var(--border)", backgroundColor: "var(--surface-hover)" }}>
                    {hasFlow && (
                        <button 
                            onClick={() => setUserTab("flow")}
                            style={{ padding: "8px 12px", border: "none", cursor: "pointer", fontWeight: "bold", backgroundColor: activeTab === "flow" ? "var(--primary)" : "transparent", color: activeTab === "flow" ? "#fff" : "var(--text)" }}
                        >Flow</button>
                    )}
                    {hasTemp && (
                        <button 
                            onClick={() => setUserTab("temp")}
                            style={{ padding: "8px 12px", border: "none", cursor: "pointer", fontWeight: "bold", backgroundColor: activeTab === "temp" ? "var(--primary)" : "transparent", color: activeTab === "temp" ? "#fff" : "var(--text)" }}
                        >Temp</button>
                    )}
                    {hasPrecip && (
                        <button 
                            onClick={() => setUserTab("precip")}
                            style={{ padding: "8px 12px", border: "none", cursor: "pointer", fontWeight: "bold", backgroundColor: activeTab === "precip" ? "var(--primary)" : "transparent", color: activeTab === "precip" ? "#fff" : "var(--text)" }}
                        >Precip</button>
                    )}
                </div>
            )}

            {/* Forecast Switch */}
            {!hasNoData && hasForecastData && (
                <div style={{ display: "flex", borderRadius: "8px", overflow: "hidden", border: "1px solid var(--border)", backgroundColor: "var(--surface-hover)", marginLeft: "auto" }}>
                    <button 
                        onClick={() => setShowForecast(!showForecast)}
                        style={{ padding: "8px 12px", border: "none", cursor: "pointer", fontWeight: "bold", backgroundColor: showForecast ? "var(--primary)" : "transparent", color: showForecast ? "#fff" : "var(--text)" }}
                    >Forecast: {showForecast ? "ON" : "OFF"}</button>
                </div>
            )}

            {/* Time Range Switch */}
            {!hasNoData && (
                <div style={{ display: "flex", borderRadius: "8px", overflow: "hidden", border: "1px solid var(--border)", backgroundColor: "var(--surface-hover)", marginLeft: (!hasNoData && hasForecastData) ? "0" : "auto" }}>
                    <button 
                        onClick={() => setTimeRange(1)}
                        style={{ padding: "8px 12px", border: "none", cursor: "pointer", fontWeight: "bold", backgroundColor: timeRange === 1 ? "var(--primary)" : "transparent", color: timeRange === 1 ? "#fff" : "var(--text)" }}
                    >1D</button>
                    <button 
                        onClick={() => setTimeRange(3)}
                        style={{ padding: "8px 12px", border: "none", cursor: "pointer", fontWeight: "bold", backgroundColor: timeRange === 3 ? "var(--primary)" : "transparent", color: timeRange === 3 ? "#fff" : "var(--text)" }}
                    >3D</button>
                    <button 
                        onClick={() => setTimeRange(7)}
                        style={{ padding: "8px 12px", border: "none", cursor: "pointer", fontWeight: "bold", backgroundColor: timeRange === 7 ? "var(--primary)" : "transparent", color: timeRange === 7 ? "#fff" : "var(--text)" }}
                    >7D</button>
                </div>
            )}
        </div>
      </div>

      {hasNoData ? (
        <div style={{ color: "var(--text-muted)", fontStyle: "italic", padding: "10px 0" }}>
          No historical graph data available for this gauge.
        </div>
      ) : (
        <>
          {isGraphStale && (
            <div style={{ 
              backgroundColor: "var(--warning-bg)", 
              color: "var(--warning-text)", 
              padding: "10px", 
              borderRadius: "8px", 
              marginBottom: "10px", 
              fontSize: "0.9em",
              textAlign: "center",
              border: "1px solid var(--warning)",
              fontWeight: "bold"
            }}>
              ⚠️ Data is more than 2 hours old. This gauge may be reporting intermittently or is currently offline.
            </div>
          )}
          <div
            style={{
              width: "100%",
              height: "300px",
              backgroundColor: "var(--surface-hover)",
              borderRadius: "8px",
              border: "1px solid #CBD5E1",
              overflow: "hidden"
            }}
          >
            <ResponsiveContainer width="100%" height={300} minWidth={1} debounce={100}>
              <LineChart
                data={data}
                margin={{ top: 5, right: 10, left: 10, bottom: 5 }}
              >
                <CartesianGrid
                  strokeDasharray="3 3"
                  stroke="var(--border)"
                />
                <XAxis
                  dataKey="dateTime"
                  tickFormatter={formatDate}
                  stroke={axisColor}
                  tick={{ fill: axisColor, fontSize: 18 }}
                  minTickGap={30}
                />
                <Tooltip content={
                    <CustomTooltip 
                        isDarkMode={isDarkMode} 
                        activeTab={activeTab} 
                        flowKey={flowKey} 
                        stageKey={stageKey} 
                        volumeColor={volumeColor}
                        stageColor={stageColor}
                        tempColor={tempColor}
                        precipColor={precipColor}
                    />
                } />

                {activeTab === "flow" && (
                  <>
                    <YAxis
                      yAxisId="left"
                      stroke={volumeColor}
                      tick={{ fill: volumeColor, fontSize: 18 }}
                      offset={10}
                      width={45}
                      domain={["auto", "auto"]}
                    />
                    <YAxis
                      yAxisId="right"
                      orientation="right"
                      stroke={stageColor}
                      tick={{ fill: stageColor, fontSize: 18 }}
                      offset={10}
                      width={45}
                      domain={["auto", "auto"]}
                    />
                    <Line
                      yAxisId="left"
                      type="monotone"
                      dataKey={flowKey}
                      name={flowKey === "cfs" ? "Flow (cfs)" : "Flow (cms)"}
                      stroke={volumeColor}
                      dot={false}
                      strokeWidth={4}
                      animationDuration={200}
                      connectNulls={true}
                    />
                    <Line
                      yAxisId="left"
                      type="monotone"
                      dataKey={`${flowKey}Forecast`}
                      stroke={volumeColor}
                      strokeDasharray="5 5"
                      dot={false}
                      strokeWidth={3}
                      animationDuration={200}
                      connectNulls={true}
                      activeDot={false}
                      legendType="none"
                    />
                    <Line
                      yAxisId="right"
                      type="monotone"
                      dataKey={stageKey}
                      name={stageKey === "ft" ? "Stage (ft)" : "Stage (m)"}
                      stroke={stageColor}
                      dot={false}
                      strokeWidth={4}
                      animationDuration={200}
                      connectNulls={true}
                    />
                    <Line
                      yAxisId="right"
                      type="monotone"
                      dataKey={`${stageKey}Forecast`}
                      stroke={stageColor}
                      strokeDasharray="5 5"
                      dot={false}
                      strokeWidth={3}
                      animationDuration={200}
                      connectNulls={true}
                      activeDot={false}
                      legendType="none"
                    />

                    {/* Threshold Lines */}
                    {(['min', 'low', 'mid', 'high', 'max'] as const).map((key, i) => {
                      const val = river.flow?.[key];
                      if (val == null || isNaN(val)) return null;

                      const isStageUnit = river.flow.unit === "ft" || river.flow.unit === "m";
                      const yAxisId = isStageUnit ? "right" : "left";

                      // Match the HSL logic from calculateColor in flowInfoCalculations.ts
                      // min=0, low=1, mid=2, high=3, max=4
                      let lightness = isDarkMode ? 35 : 50;
                      if (!isDarkMode && i === 1) lightness = 40; // Specifically darken yellow for contrast
                      const strokeColor = `hsl(${i * 60}, 100%, ${lightness}%)`;

                      return (
                        <ReferenceLine
                          key={key}
                          yAxisId={yAxisId}
                          y={val}
                          stroke={strokeColor}
                          strokeWidth={2}
                          strokeDasharray="5 5"
                          label={{
                            position: 'insideLeft',
                            value: `${key.charAt(0).toUpperCase() + key.slice(1)} (${val})`,
                            fill: isDarkMode ? "#cbd5e1" : "#475569",
                            fontSize: 14,
                            fontWeight: 'bold',
                            dy: -10
                          }}
                        />
                      );
                    })}
                  </>
                )}

                {activeTab === "temp" && (
                  <>
                    <YAxis
                      stroke={tempColor}
                      tick={{ fill: tempColor, fontSize: 18 }}
                      width={45}
                      domain={["auto", "auto"]}
                    />
                    <Line
                      type="monotone"
                      dataKey="temp"
                      name="Temperature"
                      stroke={tempColor}
                      dot={false}
                      strokeWidth={4}
                      animationDuration={200}
                      connectNulls={true}
                    />
                  </>
                )}

                {activeTab === "precip" && (
                  <>
                    <YAxis
                      stroke={precipColor}
                      tick={{ fill: precipColor, fontSize: 18 }}
                      width={45}
                      domain={[0, "auto"]}
                    />
                    <Line
                      type="monotone"
                      dataKey="precip"
                      name="Precipitation"
                      stroke={precipColor}
                      dot={false}
                      strokeWidth={4}
                      animationDuration={200}
                      connectNulls={true}
                    />
                  </>
                )}
              </LineChart>
            </ResponsiveContainer>
          </div>



          {activeTab === "precip" && precipSummary && (
            <p
              style={{
                textAlign: "center",
                color: precipColor,
                marginTop: "10px",
                fontSize: "0.9em",
                fontWeight: "bold",
              }}
            >
              {precipSummary}
            </p>
          )}

        </>
      )}
    </div>
  );
};

import React, { createContext, useContext, useEffect, useState } from "react";
import { persistentStorage } from "../utils/persistentStorage";

interface SettingsContextType {
  isDarkMode: boolean;
  isColorBlindMode: boolean;
  homePageDefaultSearch: string | null;
  quickActionPref: string;
  updateSetting: (key: string, value: string | null) => void;
  loading: boolean;
  themePref: string | null;
  colorBlindPref: string | null;
  flowUnits: string;
  tempUnits: string;
  precipUnits: string;
}

const SettingsContext = createContext<SettingsContextType>({
  isDarkMode: false,
  isColorBlindMode: false,
  homePageDefaultSearch: null,
  quickActionPref: "favorites",
  updateSetting: () => {},
  loading: true,
  themePref: null,
  colorBlindPref: null,
  flowUnits: "default",
  tempUnits: "imperial",
  precipUnits: "imperial",
});

export const SettingsProvider: React.FC<{ children: React.ReactNode }> = ({
  children,
}) => {
  const [loading, setLoading] = useState(true);
  const [themePref, setThemePref] = useState<string | null>(null);
  const [colorBlindPref, setColorBlindPref] = useState<string | null>(null);
  const [defaultSearchPref, setDefaultSearchPref] = useState<string | null>(null);
  const [quickActionState, setQuickActionState] = useState<string>("favorites");
  const [flowUnits, setFlowUnits] = useState<string>("default");
  const [tempUnits, setTempUnits] = useState<string>("imperial");
  const [precipUnits, setPrecipUnits] = useState<string>("imperial");

  const [systemDark, setSystemDark] = useState(() => {
    if (typeof window !== "undefined")
      return window.matchMedia("(prefers-color-scheme: dark)").matches;
    return false;
  });

  useEffect(() => {
    async function init() {
      let qap = await persistentStorage.get("quickActionPref") || await persistentStorage.get("starActionPref");
      if (qap === "ask") qap = "favorites";
      setQuickActionState(qap || "favorites");
      setFlowUnits(await persistentStorage.get("flowUnits") || "default");
      setTempUnits(await persistentStorage.get("tempUnits") || "imperial");
      setPrecipUnits(await persistentStorage.get("precipUnits") || "imperial");
      setLoading(false);
    }
    init();

    const minterface = window.matchMedia("(prefers-color-scheme: dark)");
    const listener = (e: MediaQueryListEvent) => {
      setSystemDark(e.matches);
    };
    minterface.addEventListener("change", listener);
    return () => {
      minterface.removeEventListener("change", listener);
    };
  }, []);

  const updateSetting = async (key: string, value: string | null) => {
    if (value === "null" || value === null) {
      await persistentStorage.remove(key);
    } else {
      await persistentStorage.set(key, value);
    }

    if (key === "userTheme") setThemePref(value === "null" ? null : value);
    if (key === "colorBlindMode")
      setColorBlindPref(value === "null" ? null : value);
    if (key === "homePageDefaultSearch")
      setDefaultSearchPref(value === "null" ? null : value);
    if (key === "quickActionPref" || key === "starActionPref")
      setQuickActionState(value === "null" || value === "ask" ? "favorites" : (value || "favorites"));
    if (key === "flowUnits") setFlowUnits(value || "default");
    if (key === "tempUnits") setTempUnits(value || "imperial");
    if (key === "precipUnits") setPrecipUnits(value || "imperial");
  };

  let isDarkMode = systemDark;
  if (themePref === "true") isDarkMode = true;
  else if (themePref === "false") isDarkMode = false;
  const isColorBlindMode = colorBlindPref === "true";
  const homePageDefaultSearch = defaultSearchPref;
  const quickActionPref = quickActionState;

  // Inject theme into root
  useEffect(() => {
    if (loading) return; // Wait until prefs load to avoid flashing light theme
    if (isDarkMode) {
      document.documentElement.setAttribute("data-theme", "dark");
      document.body.classList.add("dark-theme");
    } else {
      document.documentElement.removeAttribute("data-theme");
      document.body.classList.remove("dark-theme");
    }
  }, [isDarkMode, loading]);

  return (
    <SettingsContext.Provider
      value={{
        isDarkMode,
        isColorBlindMode,
        homePageDefaultSearch,
        quickActionPref,
        updateSetting,
        loading,
        themePref,
        colorBlindPref,
        flowUnits,
        tempUnits,
        precipUnits,
      }}
    >
      {children}
    </SettingsContext.Provider>
  );
};

export const useSettings = () => useContext(SettingsContext);

import { useState, useEffect, useMemo } from "react";
import type { RiverData, GaugeReading } from "../types/River";
import { calculateRelativeFlow } from "../utils/flowInfoCalculations";
import { FLOW_API_URL } from "../services/api";

const dynamicFlowCache = new Map<string, { lastFetchedMs: number; gaugeData: Record<string, GaugeReading[]>; gaugeNames?: Record<string, string> }>();

/**
 * useDynamicFlow
 * Fetches 7 days of historical flow data + forecasts on-demand for all gauge providers.
 * Used primarily for the "Search Discovery" detailed view and River Details page.
 */
export function useDynamicFlow(river: RiverData) {
  const [dynamicPayload, setDynamicPayload] = useState<{ gaugeData: Record<string, GaugeReading[]>; gaugeNames?: Record<string, string> } | null>(null);

  useEffect(() => {
    if (!river.gauges || river.gauges.length === 0) return;

    const allGauges = river.gauges.map(g => g.id);
    const cacheKey = allGauges.toSorted((a, b) => a.localeCompare(b)).join(",");
    const cached = dynamicFlowCache.get(cacheKey);

    const primaryGaugeID = river.gauges?.find((g: any) => g.isPrimary)?.id || river.gauges?.[0]?.id;
    const existingDatasetLength = primaryGaugeID && river.gaugeData?.[primaryGaugeID]?.length ? river.gaugeData[primaryGaugeID].length : 0;
    const existingFirstTime = primaryGaugeID && river.gaugeData?.[primaryGaugeID]?.[0]?.dateTime ? river.gaugeData[primaryGaugeID][0].dateTime : 0;
    const existingLastTime = primaryGaugeID && river.gaugeData?.[primaryGaugeID]?.[existingDatasetLength - 1]?.dateTime ? river.gaugeData[primaryGaugeID][existingDatasetLength - 1].dateTime : 0;

    // We consider the data "fresh enough" if it covers at least 6.5 days and was fetched in the last 15 mins
    const hasSevenDays = existingDatasetLength > 0 && 
       (existingLastTime - existingFirstTime >= 6.5 * 24 * 60 * 60 * 1000);

    const newlyFetched = cached && (Date.now() - cached.lastFetchedMs < 15 * 60 * 1000);

    if (hasSevenDays && newlyFetched && cached) {
       setDynamicPayload({ gaugeData: cached.gaugeData, gaugeNames: cached.gaugeNames });
       return;
    }

    let isMounted = true;

    const fetchGauges = async () => {
      try {
        const gaugeDataMap: Record<string, Map<number, any>> = {};
        const siteNameMap: Record<string, string> = {};

        if (allGauges.length === 0) return;

        // Fetch 7 days + Forecasts from unified flow API
        const url = `${FLOW_API_URL}/history?gauges=${allGauges.join(",")}&days=7&forecast=true`;
        const res = await fetch(url);

        if (!res.ok) {
            const errorText = await res.text();
            throw new Error(`Flow API error: ${res.status} ${errorText}`);
        }

        const data = await res.json();

        for (const [gaugeId, gaugeInfo] of Object.entries(data) as [string, any][]) {
            if (!gaugeDataMap[gaugeId]) gaugeDataMap[gaugeId] = new Map();

            if (gaugeInfo.name && !siteNameMap[gaugeId]) {
                siteNameMap[gaugeId] = gaugeInfo.section ? `${gaugeInfo.name} ${gaugeInfo.section}` : gaugeInfo.name;
            }

            if (gaugeInfo.readings) {
                for (const reading of gaugeInfo.readings) {
                    const ts = reading.dateTime;
                    gaugeDataMap[gaugeId].set(ts, { ...reading });
                }
            }
        }

        if (!isMounted) return;

        // Merge with existing gaugeData
        const mergedGaugeData: Record<string, GaugeReading[]> = {};

        for (const [gaugeId, map] of Object.entries(gaugeDataMap)) {
            const sortedLive = Array.from(map.values()).sort((a, b) => a.dateTime - b.dateTime);
            const cachedDataset = [...(river.gaugeData?.[gaugeId] || [])];

            for (const liveReading of sortedLive) {
                const matchIndex = cachedDataset.findIndex(item => item.dateTime === liveReading.dateTime);
                if (matchIndex >= 0) {
                   cachedDataset[matchIndex] = { ...cachedDataset[matchIndex], ...liveReading };
                } else {
                   cachedDataset.push(liveReading as GaugeReading);
                }
            }
            cachedDataset.sort((a, b) => a.dateTime - b.dateTime);
            mergedGaugeData[gaugeId] = cachedDataset;
        }

        dynamicFlowCache.set(cacheKey, { lastFetchedMs: Date.now(), gaugeData: mergedGaugeData, gaugeNames: siteNameMap });
        setDynamicPayload({ gaugeData: mergedGaugeData, gaugeNames: siteNameMap });

      } catch (err: unknown) {
        if (isMounted && err instanceof Error) console.error("Dynamic Gauge Fetch Error:", err.message);
      }
    };

    const timeoutId = setTimeout(fetchGauges, 300);

    return () => { 
        isMounted = false;
        clearTimeout(timeoutId);
    };
  }, [river.id, river.gauges?.map(g => g.id).join(",")]);

  const enrichedRiver = useMemo(() => {
    if (!dynamicPayload) return null;

    const enriched = { ...river };
    enriched.gaugeData = { ...(enriched.gaugeData || {}), ...dynamicPayload.gaugeData };

    const names = dynamicPayload.gaugeNames;
    if (names && enriched.gauges) {
        enriched.gauges = enriched.gauges.map(g => {
            if (names[g.id]) return { ...g, name: names[g.id] };
            return g;
        });
    }

    const primaryGaugeID = enriched.gauges?.find((g: any) => g.isPrimary)?.id || enriched.gauges?.[0]?.id;
    const primaryData = primaryGaugeID && enriched.gaugeData[primaryGaugeID] ? enriched.gaugeData[primaryGaugeID] : null;

    let latest = null;
    if (primaryData && primaryData.length > 0) {
        for (let i = primaryData.length - 1; i >= 0; i--) {
            // Favor non-forecast points for "latest" display logic if available
            if (!primaryData[i].forecast && (primaryData[i].cfs !== undefined || primaryData[i].ft !== undefined)) {
                latest = primaryData[i];
                break;
            }
        }
    }

    if (latest) {
        const ageInMs = Date.now() - latest.dateTime;
        enriched.isReadingStale = ageInMs > 2 * 60 * 60 * 1000;

        enriched.cfs = latest.cfs ?? enriched.cfs;
        const ftValue = latest.ft;
        enriched.ft = (ftValue !== undefined && !isNaN(ftValue)) ? ftValue : enriched.ft;
        enriched.running = calculateRelativeFlow(enriched) ?? enriched.running;

        if (enriched.cfs && enriched.ft) enriched.flowInfo = `${Math.round(enriched.cfs)}cfs, ${Math.round(enriched.ft * 100) / 100}ft`;
        else if (enriched.cfs) enriched.flowInfo = `${Math.round(enriched.cfs)}cfs`;
        else if (enriched.ft) enriched.flowInfo = `${Math.round(enriched.ft * 100) / 100}ft`;
    }

    return enriched;
  }, [river, dynamicPayload]);

  return enrichedRiver;
}

import { useState, useEffect, useMemo } from "react";
import type { RiverData } from "../types/River";
import { calculateRelativeFlow } from "../utils/flowInfoCalculations";
import { fetchAPI, fetchFlowData } from "../services/api";
import { useSettings } from "../context/SettingsContext";
import { applyUnitSettings, applyUnitSettingsToReadings } from "../utils/unitConversions";

import { deriveRegionMap, type CountryCode } from "../utils/regions";

interface UseRiversResult {
  rivers: RiverData[];
  loading: boolean;
  error: string | null;
  isGlobalStale: boolean;
  dataGeneratedAt: number | null;
  lastFetchTime: number | null;
  stateToCountryMap: Map<string, Set<CountryCode>> | null;
  availableStates: string[];
  refresh: () => Promise<void>;
}

// Global cache to prevent re-fetching on navigation between Home and Map
let globalRiversCache: RiverData[] | null = null;
let globalDataGeneratedAt: number | null = null;
let globalLastFetchTime: number | null = null;
let globalLoading = false;
let globalError: string | null = null;
let globalStateToCountryMap: Map<string, Set<CountryCode>> | null = null;
let globalAvailableStates: string[] = [];
const fetchSubscribers: Set<() => void> = new Set();

const notifySubscribers = () => {
    fetchSubscribers.forEach(fn => fn());
};

const enrichRiver = (river: any, _index: number, flowData: any, settings: any) => {
  const primaryGauge = river.gauges?.find((g: any) => g.isPrimary) || river.gauges?.[0];
  const activeGaugeId = primaryGauge?.id;
  const gaugeRecord = activeGaugeId ? flowData[activeGaugeId] : null;

  const { flowUnits } = settings;

  river.gaugeData = {};

  if (river.gauges && Array.isArray(river.gauges)) {
      river.gauges.forEach((g: any) => {
          if (flowData[g.id]) {
              if (flowData[g.id].name) g.name = String(flowData[g.id].name);
              if (flowData[g.id].section) g.section = String(flowData[g.id].section);
              if (flowData[g.id].readings) {
                  river.gaugeData![g.id] = applyUnitSettingsToReadings(flowData[g.id].readings, settings);
              }
          }
      });
  }

  if (gaugeRecord && gaugeRecord.readings && gaugeRecord.readings.length > 0) {
    const rawLatest = gaugeRecord.readings[gaugeRecord.readings.length - 1];

    // 2-hour relative staleness rule: Reading must be within 2 hours of the sync generation
    const readingAgeFromSync = (flowData.generatedAt || Date.now()) - rawLatest.dateTime;
    if (readingAgeFromSync > 2 * 60 * 60 * 1000) {
        river.isReadingStale = true;
    }

    const latest = applyUnitSettings(rawLatest, settings);

    river.cfs = latest.cfs;
    river.ft = latest.ft;

    river.m = latest.m;
    river.cms = latest.cms;

    river.running = calculateRelativeFlow(river);

    // Build specialized flowInfo based on user preferences
    const showMetric = flowUnits === "metric" || (flowUnits === "default" && latest.cms !== undefined && latest.cfs === undefined);

    if (showMetric) {
        if (latest.cms !== undefined && latest.m !== undefined)
            river.flowInfo = `${Math.round(latest.cms)}cms, ${Math.round(latest.m * 100) / 100}m`;
        else if (latest.cms !== undefined) river.flowInfo = `${Math.round(latest.cms)}cms`;
        else if (latest.m !== undefined) river.flowInfo = `${Math.round(latest.m * 100) / 100}m`;
    } else {
        if (latest.cfs !== undefined && latest.ft !== undefined)
            river.flowInfo = `${Math.round(latest.cfs)}cfs, ${Math.round(latest.ft * 100) / 100}ft`;
        else if (latest.cfs !== undefined) river.flowInfo = `${Math.round(latest.cfs)}cfs`;
        else if (latest.ft !== undefined) river.flowInfo = `${Math.round(latest.ft * 100) / 100}ft`;
    }
  }
  return river;
};

const buildStandaloneGauge = (gaugeId: string, gaugeData: any, settings: any): RiverData | null => {
   const gData: any = gaugeData;
   if (!gData.readings || gData.readings.length === 0) return null;

   const rawLatest = gData.readings[gData.readings.length - 1];

   // 2-hour relative staleness rule
   const readingAgeFromSync = (gaugeData.generatedAt || Date.now()) - rawLatest.dateTime;
   const isStale = readingAgeFromSync > 2 * 60 * 60 * 1000;

   const latest = applyUnitSettings(rawLatest, settings);
   const { flowUnits } = settings;
   let flowStr = "";
   const showMetric = flowUnits === "metric" || (flowUnits === "default" && latest.cms !== undefined && latest.cfs === undefined);

   if (showMetric) {
      if (latest.cms !== undefined && latest.m !== undefined) flowStr = `${Math.round(latest.cms)}cms, ${Math.round(latest.m * 100) / 100}m`;
      else if (latest.cms !== undefined) flowStr = `${Math.round(latest.cms)}cms`;
      else if (latest.m !== undefined) flowStr = `${Math.round(latest.m * 100) / 100}m`;
   } else {
      if (latest.cfs !== undefined && latest.ft !== undefined) flowStr = `${Math.round(latest.cfs)}cfs, ${Math.round(latest.ft * 100) / 100}ft`;
      else if (latest.cfs !== undefined) flowStr = `${Math.round(latest.cfs)}cfs`;
      else if (latest.ft !== undefined) flowStr = `${Math.round(latest.ft * 100) / 100}ft`;
   }

   const lat = Array.isArray(gData.lat) ? gData.lat[0] : gData.lat;
   const lon = Array.isArray(gData.lon) ? gData.lon[0] : gData.lon;
   const finalLat = typeof lat === 'string' ? parseFloat(lat) : lat;
   const finalLon = typeof lon === 'string' ? parseFloat(lon) : lon;

   return {
       id: gaugeId,
       name: String(gData.name || gaugeId),
       section: String(gData.section || ""),
       gauges: [{ id: gaugeId, isPrimary: true, name: String(gData.name || gaugeId), section: String(gData.section || "") }],
       isGauge: true,
       isReadingStale: isStale,
       cfs: latest.cfs,
       ft: latest.ft,
       cms: latest.cms,
       m: latest.m,
       gaugeData: { [gaugeId]: gData.readings },
       flowInfo: flowStr,
       accessPoints: !isNaN(finalLat) && !isNaN(finalLon) ? [{lat: finalLat, lon: finalLon, name: "Gauge Marker", type: "other"}] : undefined,
       skill: "?" // Standalone gauges have no rated skill
   } as unknown as RiverData;
};

const BOOTSTRAP_KEY = "rivers_bootstrap_v1";

export const useRivers = (): UseRiversResult => {
  const [rivers, setRivers] = useState<RiverData[]>(globalRiversCache || []);
  const [loading, setLoading] = useState(globalRiversCache === null ? true : globalLoading);
  const [error, setError] = useState<string | null>(globalError);
  const [dataGeneratedAt, setDataGeneratedAt] = useState<number | null>(globalDataGeneratedAt);
  const [lastFetchTime, setLastFetchTime] = useState<number | null>(globalLastFetchTime);
  const [availableStates, setAvailableStates] = useState<string[]>(globalAvailableStates);
  const [tick, setTick] = useState(0); // 5-minute heartbeat trigger
  const settings = useSettings();

  const isGlobalStale = useMemo(() => {
    // Re-evaluate on every heartbeat tick
    if (!dataGeneratedAt) return false;
    return (Date.now() - dataGeneratedAt) > 60 * 60 * 1000; // 1 hour
  }, [dataGeneratedAt, tick]);

  useEffect(() => {
    // Attempt bootstrap from localStorage if global cache is empty
    if (!globalRiversCache) {
        const cached = localStorage.getItem(BOOTSTRAP_KEY);
        if (cached) {
            try {
                const parsed = JSON.parse(cached);
                if (parsed.rivers && parsed.ts) {
                    globalRiversCache = parsed.rivers;
                    globalDataGeneratedAt = parsed.ts;

                    // Re-calculate derived region data on bootstrap
                    globalStateToCountryMap = deriveRegionMap(globalRiversCache!);
                    globalAvailableStates = Array.from(new Set(globalRiversCache!.flatMap(r => (r.states || "").split(/[ ,]+/).filter(Boolean).map(s => s.toUpperCase())))).sort((a, b) => a.localeCompare(b));

                    setRivers(globalRiversCache!);
                    setDataGeneratedAt(globalDataGeneratedAt);
                    setAvailableStates(globalAvailableStates);
                    setLoading(false);
                }
            } catch {
                console.warn("Failed to parse cached bootstrap data. Falling back to live fetch.");
            }
        }
    }

    // 5-minute heartbeat to re-calculate staleness banners
    const heartbeatId = setInterval(() => {
        setTick(t => t + 1);
    }, 5 * 60 * 1000);

    // Subscribe to global state changes
    const handleUpdate = () => {
        setRivers(globalRiversCache || []);
        setLoading(globalLoading);
        setError(globalError);
        setDataGeneratedAt(globalDataGeneratedAt);
        setLastFetchTime(globalLastFetchTime);
        setAvailableStates(globalAvailableStates);
    };
    fetchSubscribers.add(handleUpdate);

    const fetchRivers = async (force = false) => {
      // If we already have fresh data (less than 15 mins old), or are already fetching, skip
      const isFresh = globalLastFetchTime && (Date.now() - globalLastFetchTime < 15 * 60 * 1000);
      if (!force && isFresh && (globalRiversCache || globalLoading)) {
          return;
      }

      globalLoading = true;
      notifySubscribers();

      // Safety timeout to prevent permanently stuck loading state
      const timeoutId = setTimeout(() => {
          if (globalLoading && (!globalRiversCache || force)) {
              globalLoading = false;
              globalError = "Request timed out. Please try again or check your connection.";
              notifySubscribers();
          }
      }, 15000);

      try {
        const [data, flowData] = await Promise.all([
          fetchAPI("/rivers"),
          fetchFlowData()
        ]);

        let processedData = data;
        let genTime: number | null = null;

        // Enrich the rivers with flow data
        if (flowData) {
          genTime = flowData.generatedAt || Date.now();
          processedData = data.map((river: any, index: number) => enrichRiver(river, index, flowData, settings));

          // Create standalone gauges for any gauge present in flow data
          const standaloneGauges: RiverData[] = [];

          for (const [gaugeId, gaugeData] of Object.entries(flowData)) {
              if (gaugeId === "generatedAt") continue;
              const standaloneGauge = buildStandaloneGauge(gaugeId, gaugeData, settings);
              if (standaloneGauge) {
                 standaloneGauges.push(standaloneGauge);
              }
          }

          processedData = [...processedData, ...standaloneGauges];
        }

        globalRiversCache = processedData;
        globalDataGeneratedAt = genTime;
        globalLastFetchTime = Date.now();

        // Re-calculate derived region data
        globalStateToCountryMap = deriveRegionMap(processedData);
        globalAvailableStates = (Array.from(new Set(processedData.flatMap((r: any) => (r.states || "").split(/[ ,]+/).filter(Boolean).map((s: string) => s.toUpperCase())))) as string[]).sort((a, b) => a.localeCompare(b));

        globalLoading = false;

        // Persist to local storage for future bootstrap
        try {
            // Strip heavy fields, descriptions to keep boot storage ultralight
            // We now KEEP standalone gauges but ensure they are minimal skeleton records
            const strippedRivers = processedData
                .map((r: any) => {
                    const skeletonValues = { ...r };
                    delete (skeletonValues as any).gaugeData;
                    delete (skeletonValues as any).writeup;
                    delete (skeletonValues as any).aw;
                    return skeletonValues;
                });
            localStorage.setItem(BOOTSTRAP_KEY, JSON.stringify({ rivers: strippedRivers, ts: genTime }));
        } catch (error) {
            console.warn("Storage quota exceeded or error caching bootstrap data", error);
        }

        clearTimeout(timeoutId);
        notifySubscribers();

      } catch (err: unknown) {
        clearTimeout(timeoutId);
        globalError = err instanceof Error ? err.message : "An error occurred";
        globalLoading = false;
        notifySubscribers();
      }
    };

    // Service Worker Broadcast Listener
    // Triggered when StaleWhileRevalidate finds fresh data in the background
    const updateChannel = new BroadcastChannel('flow-data-updates');
    updateChannel.onmessage = (_event) => {
        console.log("Service Worker broadcast: Fresh flow data available. Refreshing UI...");
        // Re-fetch with force=true to pull fresh data from the updated cache
        // We add a tiny delay to ensure the SW has finished writing to cache
        setTimeout(() => fetchRivers(true), 100);
    };

    // Auto-fetch on refocus/visibility if data is > 15 mins old
    const handleVisibility = () => {
        if (document.visibilityState === 'visible') {
            fetchRivers();
        }
    };
    document.addEventListener('visibilitychange', handleVisibility);

    fetchRivers();

    return () => {
        fetchSubscribers.delete(handleUpdate);
        clearInterval(heartbeatId);
        document.removeEventListener('visibilitychange', handleVisibility);
        updateChannel.close();
    };
  }, []);

  const refresh = async () => {
      globalLoading = false;
      globalError = null;
      globalRiversCache = null;
      // We don't use the inner fetchRivers because of useEffect closure, but navigation or mount will trigger it.
      // Or we can manually trigger it here if we expose it.
      window.location.reload(); // Simplest "Update" button implementation for now
  };

  return { 
    rivers, 
    loading, 
    error, 
    isGlobalStale, 
    dataGeneratedAt, 
    lastFetchTime, 
    stateToCountryMap: globalStateToCountryMap,
    availableStates,
    refresh 
  };
};

import React, { useEffect, useState, useMemo, useRef } from "react";
import { RiverItem } from "../components/RiverItem";
import { TopBar } from "../components/TopBar";
import { SearchOverlay } from "../components/SearchOverlay";

import { useLocation } from "../hooks/useLocation";
import { ViewSelector } from "../components/ViewSelector";
import { useSearchParams, useParams, useLocation as useRouterLocation, useNavigate } from "react-router-dom";
import { fetchAPI } from "../services/api";
import { useRivers } from "../hooks/useRivers";
import { useLists, type UserList } from "../context/ListsContext";
import { ListEditorModal } from "../components/ListEditorModal";
import {
  calculateColor,
} from "../utils/flowInfoCalculations";
import {
  filterRivers,
  defaultAdvancedSearchQuery,
  hasActiveFilters,
} from "../utils/SearchFilters";
import type { AdvancedSearchQuery } from "../utils/SearchFilters";
import { useSettings } from "../context/SettingsContext";
import { useModal } from "../context/ModalContext";
import { triggerReviewIfEligible } from "../utils/appReview";


const LazyRiverPage = React.lazy(() => import("./RiverPage"));

const Home: React.FC = () => {
  const { isDarkMode, isColorBlindMode } = useSettings();
  const { alert } = useModal();
  const { id } = useParams<{ id: string }>();
  const routeLocation = useRouterLocation();
  const navigate = useNavigate();

  const isListOverlay = routeLocation.pathname.startsWith("/lists/") && !!id;
  const isRiverOverlay = !isListOverlay && !!id;

  const [sharedList, setSharedList] = useState<UserList | null>(null);
  const [showListModal, setShowListModal] = useState(false);
  const { createList } = useLists();

  useEffect(() => {
     if (isListOverlay && id) {
        const fetchSharedList = async () => {
            try {
               const data = await fetchAPI(`/lists/${id}`);
               if (data) {
                  setSharedList(data as UserList);
                  setShowListModal(true);
               } else {
                  await alert("This list could not be found. It may have been deleted.");
                  navigate("/");
               }
           } catch (e) {
              console.error(e);
              navigate("/");
           }
        };
        fetchSharedList();
     } else {
        setShowListModal(false);
        setSharedList(null);
     }
  }, [isListOverlay, id, navigate]);

   const { rivers, loading: riversLoading, error: riversError, isGlobalStale, dataGeneratedAt, refresh } = useRivers();
   const { syncError: listSyncError, refreshCloudState } = useLists();
   const [loading, setLoading] = useState(true);
   const [error, setError] = useState<string | null>(null);

   // Sync internal loading state with rivers data hook
   useEffect(() => {
      // We only want to show the full-page loader if we have NO rivers and are fetching
      if (riversLoading && rivers.length === 0) {
          setLoading(true);
      } else {
          setLoading(false);
          if (riversError) setError(riversError);
      }
   }, [riversLoading, riversError, rivers.length]);

  const [searchParams] = useSearchParams();

  // Search State
  const [searchQuery, setSearchQuery] = useState<AdvancedSearchQuery>(() => {
    const q = { ...defaultAdvancedSearchQuery };
    const searchParamVal = searchParams.get("search");
    if (searchParamVal) {
      q.normalSearch = searchParamVal;
    }

    const nameVal = searchParams.get("name");
    if (nameVal) q.name = nameVal;

    const sectionVal = searchParams.get("section");
    if (sectionVal) q.section = sectionVal;

    const distMax = searchParams.get("distanceMax");
    if (distMax) {
        q.distanceMax = parseInt(distMax);
        q.mapRadiusMode = (searchParams.get("radiusMode") as "current" | "center" | "custom" | null) || "current";
        const customLat = searchParams.get("userLat");
        const customLon = searchParams.get("userLon");
        if (customLat) q.userLat = parseFloat(customLat);
        if (customLon) q.userLon = parseFloat(customLon);
    }

    const favOnly = searchParams.get("favoritesOnly");
    if (favOnly) q.favoritesOnly = favOnly === "true";

    const sMin = searchParams.get("skillMin");
    if (sMin) q.skillMin = parseInt(sMin);

    const sMax = searchParams.get("skillMax");
    if (sMax) q.skillMax = parseInt(sMax);

    const fMin = searchParams.get("flowMin");
    if (fMin) q.flowMin = parseFloat(fMin);

    const fMax = searchParams.get("flowMax");
    if (fMax) q.flowMax = parseFloat(fMax);

    const sortByVal = searchParams.get("sortBy") as AdvancedSearchQuery["sortBy"];
    if (sortByVal) {
      q.sortBy = sortByVal;
    } else if (searchParamVal) {
      q.sortBy = "none";
    }

    const countryVal = searchParams.get("country");
    if (countryVal) q.country = countryVal;

    const sortReverseVal = searchParams.get("sortReverse");
    if (sortReverseVal) q.sortReverse = sortReverseVal === "true";

    return q;
  });

  const [isAdvancedSearchOpen, setIsAdvancedSearchOpen] = useState(false);
  const [listTitle, setListTitle] = useState<string | null>(null);

  // Load persistence settings and list data
  useEffect(() => {
    async function loadPersistence() {
      const { persistentStorage } = await import("../utils/persistentStorage");

      const defaultSearch = await persistentStorage.get("homePageDefaultSearch");
      if (defaultSearch === "favorites") {
        setSearchQuery(prev => ({ ...prev, favoritesOnly: true }));
      }

      const listParam = searchParams.get("list");
      let targetListId = listParam;
      if (!targetListId && defaultSearch && defaultSearch.startsWith("list:")) {
          targetListId = defaultSearch.replace("list:", "");
      }

      if (targetListId) {
        setLoading(true);

        // Attempt to load from cache immediately to guarantee offline UX
        const cachedListStr = await persistentStorage.get(`saved_list_${targetListId}`);
        if (cachedListStr) {
            try {
                const cachedData = JSON.parse(cachedListStr);
                setSearchQuery((prev) => ({ ...prev, listId: targetListId, listData: cachedData.rivers || [] }));
                setListTitle(cachedData.title);
            } catch {
               // Silently catch json parse err
            }
        }

        try {
            const data = await fetchAPI(`/lists/${targetListId}`);
            if (data) {
               setSearchQuery((prev) => ({ ...prev, listId: targetListId, listData: data.rivers || [] }));
               setListTitle(data.title);
               // Save it for offline
               await persistentStorage.set(`saved_list_${targetListId}`, JSON.stringify(data));
            } else if (!cachedListStr) {
               let foundOffline = false;
               const customListsCache = await persistentStorage.get("my_custom_lists");
               if (customListsCache) {
                 try {
                   const lists = JSON.parse(customListsCache);
                   const found = lists.find((l: any) => l.id === targetListId);
                   if (found) {
                     setSearchQuery((prev) => ({ ...prev, listId: targetListId, listData: found.rivers || [] }));
                     setListTitle(found.title);
                     foundOffline = true;
                   }
                 } catch {}
               }
               if (!foundOffline) {
                  setError("Requested list does not exist.");
                  // Clear the broken list filter so the site remains usable
                  setSearchQuery((prev) => ({ ...prev, listId: undefined, listData: undefined }));
               }
            }
        } catch (err: unknown) {
            if (err instanceof Error) console.error("Failed to load list from network, trying to rely on cache", err.message);
            // If network failed and we have no cache, clear the filter so they see something
            if (!cachedListStr) {
               setSearchQuery((prev) => ({ ...prev, listId: undefined, listData: undefined }));
            }
        } finally {
            setLoading(false);
        }
      }
    }
    loadPersistence();
  }, [searchParams]);

  const location = useLocation();

  // Evaluate "current location" requests if a shared link or default search relies on runtime proximity
  useEffect(() => {
    if (searchQuery.distanceMax && (!searchQuery.mapRadiusMode || searchQuery.mapRadiusMode === "current") && searchQuery.userLat === undefined) {
      if (location.latitude && location.longitude) {
         setSearchQuery(prev => ({ ...prev, userLat: location.latitude!, userLon: location.longitude! }));
      } else if (!location.loading && !location.error) {
         location.requestLocation();
      }
    }
  }, [searchQuery.distanceMax, searchQuery.mapRadiusMode, searchQuery.userLat, location.latitude, location.longitude, location.loading, location.error]);


  const { isRiverInQuickList } = useLists();

  const filteredRivers = useMemo(() => {
    let result = filterRivers(rivers, searchQuery);
    if (searchQuery.favoritesOnly) {
      result = result.filter((r) => isRiverInQuickList(r.id, "favorites"));
    }
    return result;
  }, [rivers, searchQuery, isRiverInQuickList]);

  // Infinite Scroll State - Purely internal, no session storage needed because we never unmount!
  const [displayCount, setDisplayCount] = useState(100);

  const isInitialFilterRef = useRef(true);

  // Reset display count when the filter actually changes, avoiding initial mount overrides
  useEffect(() => {
    if (isInitialFilterRef.current) {
        isInitialFilterRef.current = false;
        return;
    }
    setDisplayCount(100);
  }, [searchQuery, isRiverInQuickList]);

  // Keep track of scroll position manually when switching to river view
  const scrollPositionRef = useRef(0);
  const prevIsRiverOverlay = useRef(isRiverOverlay);

  useEffect(() => {
    if (isRiverOverlay) {
       // Save position precisely when mounting overlay
       scrollPositionRef.current = window.scrollY || document.documentElement.scrollTop;
       window.scrollTo(0, 0);
    } else {
       // Instantly restore when closing overlay
       window.scrollTo(0, scrollPositionRef.current);
       // Trigger review prompt option when navigating back from a river view
       if (prevIsRiverOverlay.current) {
         triggerReviewIfEligible();
       }
    }
    prevIsRiverOverlay.current = isRiverOverlay;
  }, [isRiverOverlay]);

  useEffect(() => {
    const handleScroll = () => {
      // Don't trigger infinite load expansion if we are currently looking at single river
      if (isRiverOverlay) return;

      const scrollY = window.scrollY || document.documentElement.scrollTop;
      const scrollHeight = document.documentElement.scrollHeight || document.body.scrollHeight;


      // If we are within 1200px of the bottom of the page
      if (
        window.innerHeight + scrollY >=
        scrollHeight - 1200
      ) {
        setDisplayCount((prev) => Math.min(prev + 50, filteredRivers.length));
      }
    };
    window.addEventListener("scroll", handleScroll);
    return () => {
      window.removeEventListener("scroll", handleScroll);
    };
  }, [filteredRivers.length, isRiverOverlay]);

  useEffect(() => {

    // Debugging only
    const gaugeCount = rivers.filter(r => r.isGauge).length;
    console.log("TOTAL GAUGES IN RIVERS:", gaugeCount, "TOTAL RIVERS:", rivers.length);
  }, [rivers]);

  const renderedRiverItems = useMemo(() => {
    return filteredRivers.slice(0, displayCount).map((river, index) => (
      <RiverItem
        key={river.id || `${river.name}-${index}`}
        river={river}
        index={index}
        isDarkMode={isDarkMode}
        isColorBlindMode={isColorBlindMode}
      />
    ));
  }, [filteredRivers, displayCount, isDarkMode, isColorBlindMode]);

  if (loading)
    return (
      <div className="page-content center">
        <h2>Loading River Data...</h2>
      </div>
    );
  if (error)
    return (
      <div className="page-content center">
        <h2>Error: {error}</h2>
      </div>
    );

  // We use the globally defined LazyRiverPage to inject the UI seamlessly without breaking Suspense

  const handleViewChange = (view: "all" | "favorites") => {
    const params = new URLSearchParams(searchParams);
    if (view === "all") {
      params.delete("favoritesOnly");
      params.delete("list");
      setListTitle(null);
    } else {
      params.set("favoritesOnly", "true");
      params.delete("list");
    }
    navigate(`/?${params.toString()}`);
  };

  const handleCountryChange = (country: string) => {
    const params = new URLSearchParams(searchParams);
    if (country === "global") {
      params.delete("country");
    } else {
      params.set("country", country);
    }
    navigate(`/?${params.toString()}`);
  };

  const regionLabels: Record<string, string> = {
    global: "Global",
    usa: "US",
    canada: "Canadian",
    france: "French",
    uk_ireland: "UK & Irish"
  };

  const regionPrefix = regionLabels[searchQuery.country || "global"] || "Global";
  const viewLabel = listTitle || (searchQuery.favoritesOnly ? "Favorites" : "Full List");

  let emptyStateTitle = "No Rivers Found";
  let emptyStateDesc = "Try adjusting your filters or search terms.";
  let emptyStateIcon = "🔍";

  if (searchQuery.favoritesOnly) {
    emptyStateTitle = "Your Favorites are Empty";
    emptyStateDesc = "Star a river from the list to save it here!";
    emptyStateIcon = "⭐";
  } else if (searchQuery.listId) {
    emptyStateTitle = "This List is Empty";
    emptyStateDesc = "Add rivers to this list using the 'Save to List' menu on any river page.";
    emptyStateIcon = "📋";
  }


  return (
    <div className="page-content">
      {/* Search List Overlay Toggle */}
      <div style={{ display: isRiverOverlay ? "none" : "block" }}>
        {listSyncError && (
          <div style={{ 
            backgroundColor: "var(--surface-hover)", 
            color: "var(--text)", 
            padding: "10px", 
            textAlign: "center", 
            borderRadius: "8px", 
            marginBottom: "15px",
            border: "1px solid var(--border)",
            fontSize: "0.85em",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            gap: "10px"
          }}>
            <span>
              Cloud lists sync failed. Using offline data.
            </span>
            <button 
              onClick={() => refreshCloudState()}
              style={{
                backgroundColor: "var(--primary)",
                color: "white",
                border: "none",
                padding: "2px 8px",
                borderRadius: "4px",
                cursor: "pointer",
                fontSize: "0.9em"
              }}
            >
              Retry
            </button>
          </div>
        )}
        {isGlobalStale && (
          <div style={{ 
            backgroundColor: "var(--warning-bg)", 
            color: "var(--warning-text)", 
            padding: "12px", 
            textAlign: "center", 
            borderRadius: "8px", 
            marginBottom: "15px",
            border: "1px solid var(--warning)",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            gap: "10px"
          }}>
            <span>
              ⚠️ Data was last synced {dataGeneratedAt ? Math.round((Date.now() - dataGeneratedAt) / 60000) : "?"} mins ago.
            </span>
            <button 
              onClick={() => refresh()}
              style={{
                backgroundColor: "var(--warning)",
                color: "var(--warning-text)",
                border: "1px solid var(--warning-text)",
                padding: "4px 12px",
                borderRadius: "4px",
                cursor: "pointer",
                fontWeight: "900"
              }}
            >
              Update
            </button>
          </div>
        )}
        <ViewSelector 
          regionLabel={regionPrefix}
          viewLabel={viewLabel}
          onSelectRegion={handleCountryChange}
          onSelectView={handleViewChange}
        />
        <div 
        className="searchcontain"
        style={{
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          gap: "10px",
          margin: "0 auto 20px auto",
          maxWidth: "700px",
          width: "100%",
          padding: "0 15px",
          boxSizing: "border-box"
        }}
      >
        <input
          id="searchbox"
          type="text"
          aria-label="Type in the box to search for a river"
          placeholder="Search for a river..."
          value={searchQuery.normalSearch || ""}
          onChange={(e) => {
            const hasText = e.target.value.trim().length > 0;
            // When typing starts (hasText), default to relevance sort ("none"). 
            // When cleared, revert back to alphabetical. 
            // Preserve explicit sorts only if they manually clicked a sort header. 
            // Since there's no easy way to know if they manually clicked vs just had the default,
            // we will strictly follow: "typing resets any sorting".
            setSearchQuery((prev) => {
              let nextSort = prev.sortBy;
              if (hasText) {
                nextSort = "none";
              } else if (prev.sortBy === "none") {
                nextSort = "alphabetical";
              }

              return { 
                ...prev, 
                normalSearch: e.target.value,
                sortBy: nextSort
              };
            });

          }}
          style={{
            flex: 1,
            padding: "10px 20px",
            fontSize: "1rem",
            borderRadius: "50px",
            border: "1px solid var(--border)",
            backgroundColor: "var(--surface)",
            color: "var(--text)",
            outline: "none",
            boxShadow: isDarkMode 
                ? "inset 0 1px 2px rgba(0,0,0,0.5)" 
                : "inset 0 1px 2px rgba(0,0,0,0.05)",
            transition: "all 0.2s"
          }}
        />
        <button
          id="advancedsearch"
          onClick={() => {
            setIsAdvancedSearchOpen(true);
          }}
          style={{
            padding: "10px 20px",
            fontSize: "0.95rem",
            fontWeight: 600,
            borderRadius: "50px",
            border: "none",
            backgroundColor: "var(--primary)",
            color: "#ffffff",
            cursor: "pointer",
            boxShadow: "0 4px 6px -1px rgba(0, 0, 0, 0.1)",
            transition: "all 0.2s"
          }}
        >
          Advanced
        </button>
      </div>

      {location.loading && (!searchQuery.mapRadiusMode || searchQuery.mapRadiusMode === "current") && searchQuery.distanceMax !== undefined && searchQuery.userLat === undefined && (
          <div style={{ textAlign: "center", marginBottom: "15px", color: "var(--text-muted)", fontSize: "0.9em" }}>
             <em>Requesting device location to evaluate shared radius search...</em>
          </div>
      )}

      {location.error && (!searchQuery.mapRadiusMode || searchQuery.mapRadiusMode === "current") && searchQuery.distanceMax !== undefined && searchQuery.userLat === undefined && (
          <div style={{ textAlign: "center", marginBottom: "15px", color: "var(--danger)", fontSize: "0.9em" }}>
             <em>Failed to get location for radius search: {location.error}</em>
          </div>
      )}

      {hasActiveFilters(searchQuery) && (
         <div style={{ textAlign: "center", marginBottom: "15px" }}>
            <span style={{ fontSize: "0.9em", color: "var(--text-muted)", fontStyle: "italic", marginRight: "10px" }}>
                Custom Filters Active
            </span>
            <button 
                onClick={() => handleViewChange("all")}
                style={{
                    padding: "4px 10px",
                    backgroundColor: "var(--danger)",
                    color: "var(--surface)",
                    border: "none",
                    borderRadius: "4px",
                    cursor: "pointer",
                    fontSize: "0.85em",
                    fontWeight: "bold"
                }}
            >
                Clear Filters (View All)
            </button>
         </div>
      )}

      <SearchOverlay
        isOpen={isAdvancedSearchOpen}
        onClose={() => {
          setIsAdvancedSearchOpen(false);
        }}
        query={searchQuery}
        setQuery={setSearchQuery}
      />

      <div
        id="legend"
        style={{
          backgroundImage: `linear-gradient(to right, ${[0, 1, 2, 3, 4].map((i) => calculateColor(i, isDarkMode, isColorBlindMode)).join(",")})`,
        }}
      >
        <span id="toolow">Too Low</span>
        <span id="lowflow">Low Flow</span>
        <span id="midflow">Mid Flow</span>
        <span id="highflow">High Flow</span>
        <span id="toohigh">Too High</span>
      </div>

      {/* Rivers List */}
      <div id="Rivers">
        <TopBar query={searchQuery} setQuery={setSearchQuery} filteredRivers={filteredRivers} />
        {filteredRivers.length === 0 && (
          <div className="empty-state-view">
            <div className="empty-state-icon">
                {emptyStateIcon}
            </div>
            <h2>
                {emptyStateTitle}
            </h2>
            <p>
                {emptyStateDesc}
            </p>
            <div className="empty-state-actions">
              <button className="clear-filters-btn" onClick={() => handleViewChange("all")}>
                  Show All Rivers
              </button>
              {(searchQuery.favoritesOnly || searchQuery.listId) && (
                <button 
                  className="secondary-action-btn" 
                  onClick={() => navigate("/lists")}
                >
                  Manage Your Lists
                </button>
              )}
            </div>
          </div>
        )}
        {renderedRiverItems}
        </div>
      </div>

      {isRiverOverlay && (
        <React.Suspense fallback={<div className="page-content center"><h2>Loading River...</h2></div>}>
           <LazyRiverPage />
        </React.Suspense>
      )}

      {showListModal && sharedList && (
         <ListEditorModal
            isOpen={showListModal}
            mode="shared"
            initialTitle={sharedList.title}
            initialDescription={sharedList.description}
            targetList={sharedList}
            onClose={() => {
              setShowListModal(false);
              navigate(`/?list=${sharedList.id}`);
            }}
            onSave={async () => {}}
            onCopySharedList={async (list) => {
               try {
                  const newId = await createList(`Copy of ${list.title}`, list.description || "", false, list.rivers);
                  if (newId) {
                      await alert("Successfully imported list to your lists!");
                      setShowListModal(false);
                      navigate(`/lists`);
                  }
               } catch (e: any) {
                  await alert(e.message);
               }
            }}
         />
      )}
    </div>
  );
};

export default Home;

import { useState, useEffect, useMemo } from "react";
import { useParams, useNavigate, useLocation } from "react-router-dom";
import { fetchAPI } from "../services/api";
import ReactQuill from "react-quill-new";
import "react-quill-new/dist/quill.snow.css"; 
import { useAuth } from "../context/AuthContext";
import { firebaseConfig } from "../firebase";
import { skillLevels, getSkillAbbreviation, getSkillIndex } from "../utils/skillTranslations";
import { RiverItem } from "../components/RiverItem";
import { validateRiver } from "../utils/riverValidation";
import { toDecimalDegrees } from "../utils/toDecimalDegrees";
import { useSettings } from "../context/SettingsContext";
import { AuthModal } from "../components/AuthModal";
import { useDynamicFlow } from "../hooks/useDynamicFlow";
import { useModal } from "../context/ModalContext";
import { useRivers } from "../hooks/useRivers";
import { ALL_STATE_CODES } from "../utils/regions";

export default function RiverEditor() {
  const { riverId, queueId } = useParams();
  const navigate = useNavigate();
  const location = useLocation();
  const { user, isAdmin } = useAuth();
  const { isDarkMode, isColorBlindMode } = useSettings();
  const { alert, confirm, prompt } = useModal();
  const { availableStates } = useRivers();

  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [showSubmitModal, setShowSubmitModal] = useState(false);

  const isNew = !riverId && !queueId;
  const isReviewMode = location.pathname.startsWith('/review') && !!queueId;
  const targetId = riverId || queueId || "";

  const stableRandomId = useMemo(() => window.crypto.getRandomValues(new Uint32Array(1))[0].toString(36), []);

  const [riverData, setRiverData] = useState<any>({
    id: targetId,
    name: "",
    states: "MD",
    class: "",
    skill: "FW",
    dam: false,
    aw: "",
    section: "",
    gauges: [],
    accessPoints: [],
    writeup: "",
    rawTags: "",
    imageUrls: [],
    flow: { unit: "cfs", min: null, low: null, mid: null, high: null, max: null }
  });

  const [liveData, setLiveData] = useState<any>(null);
  const [proposedData, setProposedData] = useState<any>(null);
  const [viewMode, setViewMode] = useState<"draft" | "original">("draft");

  const syncInputs = (inputData: any) => {
      if (!inputData) return;
      // Rigorously deep clone to completely sever object references
      const data = JSON.parse(JSON.stringify(inputData));

      const rawAccessPoints = Array.isArray(data.accessPoints) ? data.accessPoints : [];
      const safeAccess = rawAccessPoints.map((ap: any) => ({ 
        ...ap, 
        rawLat: ap.lat ? String(ap.lat) : "", 
        rawLon: ap.lon ? String(ap.lon) : "" 
      }));

      setRiverData({
        id: data.id || targetId,
        name: data.name || "",
        states: typeof data.states === 'string' ? data.states : "MD",
        class: data.class || "I",
        skill: getSkillAbbreviation(data.skill || "FW"),
        dam: data.dam || false,
        aw: data.aw || "",
        section: data.section || "",
        gauges: Array.isArray(data.gauges) ? data.gauges : [],
        accessPoints: safeAccess,
        writeup: data.writeup || "",
        rawTags: (() => {
          if (Array.isArray(data.tags)) return data.tags.join(", ");
          if (typeof data.tags === "string") return data.tags;
          return "";
        })(),
        imageUrls: Array.isArray(data.imageUrls) ? data.imageUrls : [],
        flow: data.flow || { unit: "cfs", min: null, low: null, mid: null, high: null, max: null }
      });
  };

  useEffect(() => {
    if (isNew) return;

    async function load() {
      setLoading(true);
      try {
        if (isReviewMode) {
           const suggestion = await fetchAPI(`/admin/queue/${queueId}`, {}, user);
           const proposed = suggestion.proposed_changes;
           proposed.queueId = suggestion.suggestion_id; 
           setProposedData(proposed);
           syncInputs(proposed);

           try {
             const live = await fetchAPI(`/rivers/${proposed.id}`, {}, user);
             setLiveData(live);
           } catch {
             console.log("No existing live data for this suggestion.");
           }
         }
         else {
            const live = await fetchAPI(`/rivers/${riverId}`, {}, user);
            setLiveData(live);
            syncInputs(live);
         }
       } catch (e: unknown) {
         if (e instanceof Error) console.error("Error loading river", e.message);
         // 404 is fine for new rivers or missing suggestions
       }
       setLoading(false);
     }
    load();
  }, [riverId, queueId, isNew, isReviewMode, navigate]);

  const quillModules = useMemo(() => {
    return {
      toolbar: {
        container: [
          [{ 'header': [1, 2, false] }],
          ['bold', 'italic', 'underline', 'strike', 'blockquote'],
          [{'list': 'ordered'}, {'list': 'bullet'}, {'indent': '-1'}, {'indent': '+1'}],
          ['link', 'image'],
          ['clean']
        ],
        handlers: {
          image: async function() {
            const url = await prompt("Please paste a Direct Image URL or a Google Drive sharing link:");
            if (!url) return;

            let finalUrl = url;
            const driveRe = /drive\.google\.com\/file\/d\/([-_A-Za-z0-9]{1,100})/;
            const dMatch = driveRe.exec(url);
            if (dMatch) {
              finalUrl = `https://www.googleapis.com/drive/v3/files/${dMatch[1]}?alt=media&key=${firebaseConfig.apiKey}`;
            } else {
              const openRe = /drive\.google\.com\/open\?id=([-_A-Za-z0-9]{1,100})/;
              const idMatch = openRe.exec(url);
              if (idMatch) finalUrl = `https://www.googleapis.com/drive/v3/files/${idMatch[1]}?alt=media&key=${firebaseConfig.apiKey}`;
            }

            // @ts-expect-error quill references internally
            const range = this.quill.getSelection(true);
            // @ts-expect-error quill references internally
            this.quill.insertEmbed(range.index, 'image', finalUrl);
            // @ts-expect-error quill references internally
            this.quill.setSelection(range.index + 1);
          }
        }
      }
    };
  }, [prompt]);

  const generateFinalObj = () => {
      const newAccessPoints: any[] = [];

      (riverData.accessPoints || []).forEach((ap: any) => {
          const parsedLat = toDecimalDegrees(ap.rawLat || ap.lat);
          const parsedLon = toDecimalDegrees(ap.rawLon || ap.lon);
          if (parsedLat !== null && parsedLon !== null) {
              newAccessPoints.push({
                  name: ap.name || "Access Point",
                  type: ap.type || "put-in",
                  lat: parsedLat,
                  lon: parsedLon
              });
          }
      });

      const parsedGauges = (riverData.gauges || []).map((g: any) => {
         let sanitized = g.id.trim().toUpperCase().replace(/\s+/g, '');
         if (!sanitized.includes(':') && sanitized.length > 0) sanitized = "USGS:" + sanitized;
         return { ...g, id: sanitized };
      }).filter((g: any) => g.id && g.id.includes(":") && g.id.split(":")[1].trim().length > 0);


      let idToSave: string;
      if (isNew) {
        const baseSlug = riverData.name.toLowerCase().replace(/[^a-z0-9]+/g, '-');
        idToSave = isAdmin ? baseSlug : `${baseSlug}-${stableRandomId}`;
      } else {
        idToSave = riverData.id;
      }

      return {
        ...riverData,
        id: idToSave,
        skill: getSkillIndex(riverData.skill),
        gauges: parsedGauges,
        tags: (riverData.rawTags || "").split(',').map((t: string) => t.trim()).filter(Boolean),
        accessPoints: newAccessPoints,
        flow: riverData.flow || { unit: "cfs", min: null, low: null, mid: null, high: null, max: null },
        updatedAt: new Date(),
        submittedBy: isReviewMode ? (proposedData?.submittedBy || user?.uid || "anonymous") : (user?.uid || "anonymous")
      };
  };

  const toggleView = (mode: "draft" | "original") => {
      if (mode === "original") {
          // Sever references by deep cloning, preserving the draft exactly as-is
          setProposedData(JSON.parse(JSON.stringify(generateFinalObj())));
          setViewMode("original");
          syncInputs(liveData);
      } else {
          setViewMode("draft");
          syncInputs(proposedData || liveData);
      }
  };

  const validatePayload = async (finalObj: any) => {
      const { isValid, errors, warnings } = validateRiver(finalObj);

      if (warnings.length > 0) {
          const proceed = await confirm(`Warning:\n${warnings.join('\n')}\n\nProceed submitting?`);
          if (!proceed) return false;
      }

      if (!isValid) {
          await alert(`Error:\n${errors.join('\n')}`);
          return false;
      }

      return true;
  };

  const handleSave = async (forceQueue: boolean = false) => {
    if (!user) {
      setShowSubmitModal(true);
      return;
    }
    await processSave(forceQueue);
  };

  const processSave = async (forceQueue: boolean = false) => {
    try {
      setSaving(true);
      const finalObj = generateFinalObj();
      if (!(await validatePayload(finalObj))) {
          setSaving(false);
          return;
      }

      const isAdminPublish = isAdmin && !forceQueue;
      const endpoint = isAdminPublish ? `/rivers/${finalObj.id}` : `/rivers/${finalObj.id}/suggest`;
      const method = isAdminPublish ? "PUT" : "POST";

      await fetchAPI(endpoint, {
        method,
        body: JSON.stringify(finalObj)
      }, user);

      await alert(isAdminPublish ? "Saved successfully!" : "Submitted successfully!");

      if (!isAdminPublish) {
         if (isAdmin) navigate("/admin");
         else navigate("/");
      } else {
         if (isNew) navigate(`/edit/${finalObj.id}`);
      }
    } catch (e: unknown) {
      if (e instanceof Error) {
          console.error(e.message);
          await alert(`Save failed: ${e.message}`);
      }
    } finally {
      setSaving(false);
    }
  };

  const handleApproveReview = async () => {
      if (!isAdmin || !proposedData?.queueId) return;
      try {
          setSaving(true);
          const finalObj = generateFinalObj();
          if (!(await validatePayload(finalObj))) {
              setSaving(false);
              return;
          }

          await fetchAPI(`/admin/queue/${proposedData.queueId}/resolve`, {
              method: "POST",
              body: JSON.stringify({ 
                  action: "approve", 
                  admin_overrides: finalObj,
                  admin_notes: "Approved via Web Editor"
              })
          }, user);

          await alert("Successfully approved!");
          navigate("/admin");
      } catch (e: unknown) {
          if (e instanceof Error) await alert(`Failed to approve natively: ${e.message}`);
          else await alert('Failed to approve natively');
          setSaving(false);
      }
  };

  const handleRejectReview = async () => {
      if (!isAdmin || !proposedData?.queueId) return;
      if (!(await confirm("Reject this submission completely?"))) return;

      try {
          setSaving(true);
          await fetchAPI(`/admin/queue/${proposedData.queueId}/resolve`, {
              method: "POST",
              body: JSON.stringify({ action: "reject" })
          }, user);
          await alert("Submission completely rejected.");
          navigate("/admin");
      } catch (e: unknown) {
          if (e instanceof Error) await alert(`Failed to reject natively: ${e.message}`);
          else await alert('Failed to reject natively');
          setSaving(false);
      }
  };

  const handleDeleteRiver = async () => {
      if (!isAdmin || isNew || isReviewMode) return;
      if (!(await confirm("Are you sure you want to delete this river? This action cannot be reversed."))) return;

      try {
          setSaving(true);
          await fetchAPI(`/rivers/${riverData.id}`, { method: "DELETE" }, user);
          await alert("River permanently deleted.");
          navigate("/admin");
      } catch (e: unknown) {
          if (e instanceof Error) await alert(`Failed to delete river natively: ${e.message}`);
          else await alert('Failed to delete river natively');
          setSaving(false);
      }
  };

  const previewStateStr = JSON.stringify(riverData);
  const memoizedPreviewBase = useMemo(() => generateFinalObj(), [previewStateStr]);
  const hydratedPreview = useDynamicFlow(memoizedPreviewBase) || memoizedPreviewBase;

  let { errors: liveErrors, warnings: liveWarnings } = validateRiver(memoizedPreviewBase);

  if (isNew) {
      // The River ID is strictly auto-generated from the name. A duplicate error here is inherently redundant.
      liveErrors = liveErrors.filter(e => !e.includes("River ID"));

      // If they haven't literally typed anything yet into the new submission, gracefully suppress the wall of red text
      if (riverData.name.trim() === "") {
         liveErrors = [];
         liveWarnings = [];
      }
  }

  if (loading) return <div className="page-content center"><h2>Loading Editor...</h2></div>;

  const isOriginalView = viewMode === "original";
  const pointerEvents = isOriginalView ? 'none' : 'auto';
  const opacity = 1;
  const hasPrimaryGauge = riverData.gauges.some((g: any) => g.isPrimary);

  return (
    <>
    <AuthModal isOpen={showAuthModal} onClose={() => setShowAuthModal(false)} />
    {showSubmitModal && (
      <div style={{ position: "fixed", top: 0, left: 0, right: 0, bottom: 0, backgroundColor: 'rgba(0,0,0,0.5)', zIndex: 200, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
         <div style={{ backgroundColor: 'var(--surface)', padding: '20px', borderRadius: '10px', maxWidth: '400px', width: '100%', position: 'relative', margin: '20px' }}>
            <button onClick={() => setShowSubmitModal(false)} style={{ position: 'absolute', top: '10px', right: '10px', background: 'transparent', border: 'none', cursor: 'pointer', fontSize: '24px', color: 'var(--text)' }}>×</button>
            <h3 style={{ marginTop: 0 }}>Almost Done!</h3>
            <p>Would you like to sign in? If you sign in, we can contact you if there are questions with this submission.</p>
            <div style={{ display: 'flex', gap: '10px', marginTop: '20px', justifyContent: 'flex-end', flexWrap: 'wrap' }}>
               <button onClick={() => { setShowSubmitModal(false); setShowAuthModal(true); }} style={{ padding: '8px 15px', backgroundColor: 'var(--primary)', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>Sign In</button>
               <button onClick={() => { setShowSubmitModal(false); processSave(false); }} style={{ padding: '8px 15px', backgroundColor: 'var(--surface-hover)', color: 'var(--text)', border: '1px solid var(--border)', borderRadius: '5px', cursor: 'pointer' }}>Submit Anonymously</button>
            </div>
         </div>
      </div>
    )}
    <div className="page-content" style={{ maxWidth: 800, margin: "0 auto", paddingBottom: "250px" }}>
      {isReviewMode && !liveData && (
          <div style={{ backgroundColor: "var(--warning-bg)", color: "var(--warning-text)", padding: '15px', borderRadius: '5px', marginBottom: '20px', fontWeight: 'bold' }}>
            {proposedData?._moveReason ? (
                <>
                    ⚠️ Removed from live database: Validation Failed!
                    <br/>
                    <span style={{ fontWeight: 'normal', fontSize: '14px', marginTop: '5px', display: 'block' }}>
                        This river was automatically evicted from the live database because it is no longer formatted correctly. Please fix the validation errors below to republish it.
                    </span>
                </>
            ) : (
                <>🌟 Completely New River Submission! No existing live data to diff against.</>
            )}
          </div>
      )}

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '25px' }}>
        <h1 style={{ margin: 0 }}>
          {(() => {
            if (isNew) return 'Create New River';
            if (isReviewMode) return `Review Edit: ${riverData.name}`;
            return `Edit: ${riverData.name}`;
          })()}
        </h1>

        {(!isNew && !isReviewMode && isAdmin) && (
          <button 
            onClick={handleDeleteRiver} 
            disabled={saving}
            style={{ padding: '8px 15px', backgroundColor: "transparent", color: "var(--danger)", border: '1px solid var(--danger)', borderRadius: '5px', fontSize: '14px', fontWeight: 'bold', cursor: saving ? 'not-allowed' : 'pointer', flexShrink: 0 }}
          >
            Delete River
          </button>
        )}
      </div>
      <hr style={{ borderColor: 'var(--border)', margin: '15px 0 20px 0' }} />

      <div style={{ display: 'flex', flexDirection: 'column', gap: '15px', pointerEvents, opacity }}>
        <div style={{ display: 'flex', gap: '15px' }}>
          <div style={{ flex: 2 }}>
            <label style={{fontWeight: 'bold', display: 'block'}}>River Name</label>
            <input 
              type="text" 
              style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }} 
              value={riverData.name} 
              placeholder="e.g. Potomac River"
              onChange={e => setRiverData({...riverData, name: e.target.value})} 
            />
          </div>
          <div style={{ flex: 1 }}>
            <label style={{fontWeight: 'bold', display: 'block'}}>Section</label>
            <input 
              type="text" 
              style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }} 
              value={riverData.section} 
              placeholder="e.g. Little Falls"
              onChange={e => setRiverData({...riverData, section: e.target.value})} 
            />
          </div>
        </div>

        <div style={{ display: 'flex', gap: '15px' }}>
          <div style={{ flex: 1 }}>
            <label style={{fontWeight: 'bold', display: 'block'}}>Class</label>
            <input 
              type="text" 
              style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }} 
              value={riverData.class} 
              placeholder="e.g. II-III+"
              onChange={e => setRiverData({...riverData, class: e.target.value})} 
            />
          </div>
          <div style={{ flex: 1 }}>
            <label style={{fontWeight: 'bold', display: 'block'}}>Skill Level</label>
            <select 
              style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }} 
              value={riverData.skill} 
              onChange={e => setRiverData({...riverData, skill: e.target.value})} 
            >
               {skillLevels.map(([code, name]) => <option key={code} value={code}>{name} ({code})</option>)}
            </select>
          </div>
          <div style={{ flex: 1 }}>
            <label style={{fontWeight: 'bold', display: 'block'}}>State/Region</label>
            <div style={{ display: "flex", flexWrap: "wrap", gap: "5px", marginBottom: riverData.states ? "5px" : "0" }}>
              {riverData.states?.split(',').map((s: string) => s.trim()).filter(Boolean).map((s: string) => (
                <span 
                  key={s} 
                  style={{ backgroundColor: "var(--primary)", color: "white", padding: "2px 6px", borderRadius: "4px", fontSize: "12px", cursor: "pointer" }}
                  onClick={() => {
                    const newState = riverData.states!.split(',').map((st: string) => st.trim()).filter((st: string) => st !== s).join(', ');
                    setRiverData({...riverData, states: newState});
                  }}
                  title="Click to remove"
                >
                  {s} &times;
                </span>
              ))}
            </div>
            <select
              style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }} 
              value="" 
              onChange={e => {
                 if (e.target.value) {
                   const curr = riverData.states?.split(',').map((s: string) => s.trim()).filter(Boolean) || [];
                   if (!curr.includes(e.target.value)) {
                     curr.push(e.target.value);
                     setRiverData({...riverData, states: curr.join(', ')});
                   }
                 }
              }} 
            >
               <option value="" disabled>Add State...</option>
               {/* Show states that actually have data first */}
               {availableStates.filter(st => !(riverData.states || "").includes(st)).map(st => <option key={st} value={st}>{st}</option>)}

               {/* Separator if we have many states */}
               <option disabled>──────────</option>

               {/* Show all other known states */}
              {ALL_STATE_CODES.filter(st => !availableStates.includes(st) && !(riverData.states || "").includes(st)).map(st => <option key={st} value={st}>{st}</option>)}
            </select>
          </div>
        </div>

        <div style={{ display: 'flex', gap: '15px' }}>

             <div style={{ flex: 1 }}>
                <label style={{fontWeight: 'bold', display: 'block'}}>AW River ID (Optional)</label>
                <input 
                  type="text" 
                  style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }} 
                  placeholder="e.g. 129"
                  value={riverData.aw} 
                  onChange={e => setRiverData({...riverData, aw: e.target.value})} 
                />
             </div>
             <div style={{ flex: 1 }}>
                <label style={{fontWeight: 'bold', display: 'block'}}>Tags</label>
                <input 
                  type="text" 
                  style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }} 
                  placeholder="e.g. classic, roadside (comma separated)"
                  value={riverData.rawTags || ""} 
                  onChange={e => setRiverData({...riverData, rawTags: e.target.value})} 
                />
             </div>
             <div style={{ display: 'flex', alignItems: 'center', marginTop: '20px' }}>
                <label style={{fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer'}}>
                   <input 
                     type="checkbox" 
                     checked={riverData.dam || false} 
                     onChange={e => setRiverData({...riverData, dam: e.target.checked})} 
                   />
                   Dam Released
                </label>
             </div>
        </div>

        <div style={{ backgroundColor: 'var(--surface-hover)', padding: '15px', borderRadius: '5px' }}>
          <label style={{fontWeight: 'bold', display: 'block', marginBottom: '10px'}}>Gauges</label>
          {(riverData.gauges || []).map((g: any, i: number) => (
            <GaugeItem 
              key={i} 
              gauge={g} 
              onUpdate={(updates) => {
                const newG = [...riverData.gauges];
                newG[i] = { ...newG[i], ...updates };
                if (updates.isPrimary) {
                  newG.forEach((gObj, idx) => { if (idx !== i) gObj.isPrimary = false; });
                }
                setRiverData({ ...riverData, gauges: newG });
              }}
              onDelete={() => {
                const newG = riverData.gauges.filter((_:any, index:number) => index !== i);
                setRiverData({ ...riverData, gauges: newG });
              }}
            />
          ))}
          <button onClick={() => {
              const newG = [...(riverData.gauges || [])];
              newG.push({ id: "USGS:", isPrimary: newG.length === 0 });
              setRiverData({...riverData, gauges: newG});
          }} style={{ padding: '8px', cursor: 'pointer' }}>+ Add Gauge</button>
        </div>

        {hasPrimaryGauge && (
          <div style={{ backgroundColor: 'var(--surface-hover)', padding: '15px', borderRadius: '5px' }}>
            <label style={{fontWeight: 'bold', display: 'flex', alignItems: 'center', marginBottom: '10px'}}>
              Flow Thresholds (Used for Color Coding)
              <span className="tooltip tooltip-bottom" style={{marginLeft: "10px", cursor: "help", color: "var(--primary)"}}>
                ⓘ
                <div className="tooltiptext" style={{ fontWeight: "normal", fontSize: "0.9em", width: "200px", lineHeight: "1.4", whiteSpace: "normal" }}>
                  Minimum: Barely runnable<br />
                  Low: Scrappy or low flow<br />
                  Runnable: Optimal flow<br />
                  High: Fast or pushy flow<br />
                  Maximum: Flood levels (Too High)
                </div>
              </span>
            </label>
            <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
              <div style={{ width: '80px' }}>
                <label style={{fontSize: '12px', display: 'block'}}>Unit</label>
                <select 
                  style={{ width: '100%', padding: '6px', height: '34px', boxSizing: 'border-box' }} 
                  value={riverData.flow?.unit || "cfs"}
                  onChange={e => setRiverData({...riverData, flow: {...riverData.flow, unit: e.target.value}})}
                >
                  <option value="cfs">cfs</option>
                  <option value="ft">ft</option>
                  <option value="m">m</option>
                  <option value="cms">cms</option>
                </select>
              </div>

              {[
                  { field: "min", label: "Minimum" },
                  { field: "low", label: "Low" },
                  { field: "mid", label: "Runnable" },
                  { field: "high", label: "High" },
                  { field: "max", label: "Maximum" }
                ].map(({ field, label }) => (
                 <div key={field} style={{ flex: 1, minWidth: '80px' }}>
                  <label style={{fontSize: '12px', display: 'block', whiteSpace: 'nowrap'}}>{label}</label>
                  <input 
                    type="number" 
                    style={{ width: '100%', padding: '6px', height: '34px', boxSizing: 'border-box' }} 
                    value={riverData.flow?.[field] ?? ""} 
                    onChange={e => setRiverData({...riverData, flow: {...riverData.flow, [field]: e.target.value ? parseFloat(e.target.value) : null}})} 
                  />
                </div>
              ))}
            </div>
          </div>
        )}

        <div style={{ backgroundColor: 'var(--surface-hover)', padding: '15px', borderRadius: '5px' }}>
          <label style={{fontWeight: 'bold', display: 'block', marginBottom: '10px'}}>Access Points</label>
          {(riverData.accessPoints || []).map((ap: any, i: number) => (
            <AccessPointItem
               key={i}
               ap={ap}
               onUpdate={(updates) => {
                  const newA = [...riverData.accessPoints];
                  newA[i] = { ...newA[i], ...updates };

                  const defaultNames = ["Put-In", "Midpoint", "Access", "Take-Out", "Access Point"];
                  if (updates.type && (!newA[i].name || defaultNames.includes(newA[i].name))) {
                      newA[i].name = ({"put-in": "Put-In", "access": "Access", "take-out": "Take-Out"} as Record<string, string>)[updates.type] || "Access";
                  }

                  setRiverData({ ...riverData, accessPoints: newA });
               }}
               onDelete={() => {
                  const newA = riverData.accessPoints.filter((_:any, index:number) => index !== i);
                  setRiverData({ ...riverData, accessPoints: newA });
               }}
            />
          ))}
          <button onClick={() => {
              const newA = [...(riverData.accessPoints || [])];
              newA.push({ type: "put-in", name: "Put-In", lat: null, lon: null, rawLat: "", rawLon: "" });
              setRiverData({...riverData, accessPoints: newA});
          }} style={{ padding: '8px', cursor: 'pointer' }}>+ Add Access Point</button>
        </div>

        <div style={{ marginTop: '20px' }}>
          <label style={{fontWeight: 'bold', display: 'block', marginBottom: '10px'}}>River Writeup & Description</label>
          <div style={{ backgroundColor: 'var(--surface-hover)', color: 'var(--text)' }}>
            <ReactQuill 
              theme="snow" 
              value={riverData.writeup || ""} 
              onChange={(val) => setRiverData({...riverData, writeup: val})}
              modules={quillModules}
              style={{ height: '300px', marginBottom: '50px' }}
            />
          </div>
        </div>
      </div>

      <div style={{ position: "fixed", bottom: 0, left: 0, right: 0, backgroundColor: "var(--surface)", borderTop: "1px solid var(--border)", zIndex: 100, padding: '15px', boxShadow: '0 -4px 10px rgba(0,0,0,0.1)', maxHeight: '60vh', overflowY: 'auto' }}>
          <div style={{ maxWidth: 800, margin: '0 auto' }}>

              <div style={{ marginBottom: '15px' }}>
                  <label style={{ fontSize: '12px', fontWeight: 'bold', textTransform: 'uppercase', color: 'var(--text-muted)'}}>Live Preview - Click to Expand</label>

                  {liveWarnings.length > 0 && (
                     <div style={{ backgroundColor: 'var(--warning-bg)', color: 'var(--warning-text)', padding: '10px', borderRadius: '5px', marginBottom: '10px', fontSize: '14px' }}>
                        <strong style={{ display: 'block', marginBottom: '5px' }}>⚠️ Warnings:</strong>
                        <ul style={{ margin: 0, paddingLeft: '20px' }}>
                           {liveWarnings.map((w, idx) => <li key={idx}>{w}</li>)}
                        </ul>
                     </div>
                  )}

                  {liveErrors.length > 0 ? (
                     <div style={{ backgroundColor: 'var(--danger)', color: 'white', padding: '15px', borderRadius: '5px', fontSize: '14px' }}>
                        <strong style={{ display: 'block', marginBottom: '5px', fontSize: '16px' }}>❌ Cannot Preview (Errors Found):</strong>
                        <ul style={{ margin: 0, paddingLeft: '20px' }}>
                           {liveErrors.map((e, idx) => <li key={idx}>{e}</li>)}
                        </ul>
                     </div>
                  ) : (
                     <div style={{ borderRadius: '10px' }}>
                        <RiverItem river={{...hydratedPreview, running: 2}} index={0} isDarkMode={isDarkMode} isColorBlindMode={isColorBlindMode} />
                     </div>
                  )}
              </div>

              {(!isNew && liveData) ? (
                 <div style={{ display: 'flex', backgroundColor: "var(--surface-hover)", borderRadius: '5px', padding: '5px', marginBottom: '15px' }}>
                    <button 
                      onClick={() => toggleView("original")} 
                      style={{ flex: 1, padding: '10px', backgroundColor: viewMode === 'original' ? "var(--primary)" : 'transparent', color: viewMode === 'original' ? 'white' : 'var(--text)', border: 'none', borderRadius: '5px', fontSize: '16px', fontWeight: 'bold' }}>
                      Original Live River
                    </button>
                    <button 
                      onClick={() => toggleView("draft")}
                      style={{ flex: 1, padding: '10px', backgroundColor: viewMode === 'draft' ? "var(--success)" : 'transparent', color: viewMode === 'draft' ? 'white' : 'var(--text)', border: 'none', borderRadius: '5px', fontSize: '16px', fontWeight: 'bold' }}>
                      Your Current Working Draft
                    </button>
                 </div>
              ) : (
                  <div style={{ textAlign: 'center', fontWeight: 'bold', marginBottom: '15px', color: proposedData?._moveReason ? 'var(--danger)' : 'var(--primary)' }}>
                      {proposedData?._moveReason ? "🛠 Fix Validation Errors to Republish" : "📝 New River Suggestion"}
                  </div>
              )}

              {isReviewMode ? (
                <div style={{ display: 'flex', gap: '15px' }}>
                  <button 
                    onClick={handleApproveReview} 
                    disabled={saving || isOriginalView}
                    style={{ flex: 1, padding: '15px', backgroundColor: "var(--success)", color: "var(--surface)", border: 'none', borderRadius: '5px', fontSize: '18px', cursor: (saving || isOriginalView) ? 'not-allowed' : 'pointer', opacity: isOriginalView ? 0.3 : 1 }}
                  >
                    {saving ? "Saving..." : "Approve and Deploy"}
                  </button>
                  <button 
                    onClick={handleRejectReview} 
                    disabled={saving || isOriginalView}
                    style={{ padding: '15px', backgroundColor: "var(--danger)", color: "var(--surface)", border: 'none', borderRadius: '5px', fontSize: '18px', cursor: (saving || isOriginalView) ? 'not-allowed' : 'pointer', opacity: isOriginalView ? 0.3 : 1 }}
                  >
                    Reject Submission
                  </button>
                </div>
              ) : (
                <div style={{ display: 'flex', gap: '15px' }}>
                  <button 
                    onClick={() => handleSave(false)} 
                    disabled={saving || isOriginalView}
                    style={{ flex: isAdmin ? 2 : 1, padding: '15px', backgroundColor: "var(--primary)", color: "var(--surface)", border: 'none', borderRadius: '5px', fontSize: '18px', cursor: (saving || isOriginalView) ? 'not-allowed' : 'pointer', opacity: isOriginalView ? 0.3 : 1 }}
                  >
                    {(() => {
                      if (saving) return "Saving...";
                      if (isAdmin) return "Publish";
                      return "Submit for Review";
                    })()}

                  </button>
                  {isAdmin && (
                    <button 
                      onClick={() => handleSave(true)} 
                      disabled={saving || isOriginalView}
                      style={{ flex: 1, padding: '15px', backgroundColor: "var(--surface-hover)", color: "var(--text)", border: '2px solid var(--border)', borderRadius: '5px', fontSize: '18px', cursor: (saving || isOriginalView) ? 'not-allowed' : 'pointer', opacity: isOriginalView ? 0.3 : 1 }}
                    >
                      Save to Queue
                    </button>
                  )}
                </div>
              )}
          </div>
      </div>
    </div>
    </>
  );
}

