import { getRiverCountries, type CountryCode } from "./regions";
import type { RiverData } from "../types/River";
import { lambert } from "./distance";

export interface AdvancedSearchQuery {
  normalSearch?: string;
  name?: string;
  section?: string;
  skillMin?: number;
  skillMax?: number;
  flowMin?: number;
  flowMax?: number;
  includeUnknownSkill?: boolean;
  includeUnknownFlow?: boolean;
  includeDams?: boolean;
  favoritesOnly?: boolean;
  distanceMax?: number;
  userLat?: number;
  userLon?: number;
  sortBy?: "none" | "alphabetical" | "skill" | "class" | "running" | "state";
  sortReverse?: boolean;
  listId?: string;
  listData?: { id: string; order: number }[];
  mapRadiusMode?: "current" | "center" | "custom";
  country?: string; // Added country filter
  stateToCountryMap?: Map<string, Set<CountryCode>>; // Injected dynamic map
}

export const defaultAdvancedSearchQuery: AdvancedSearchQuery = {
  normalSearch: "",
  skillMin: 1,
  skillMax: 8,
  flowMin: 0,
  flowMax: 4,
  includeUnknownSkill: true,
  includeUnknownFlow: true,
  includeDams: true,
  sortBy: "alphabetical",
  sortReverse: false,
};

export function hasActiveFilters(query: AdvancedSearchQuery): boolean {
  if (query.favoritesOnly === true) return true;
  if (query.listId && query.listId.trim() !== "") return true;
  if (query.listData && query.listData.length > 0) return true;
  if (query.distanceMax != null && query.distanceMax <= 500) return true;
  if (query.name && query.name.trim() !== "") return true;
  if (query.section && query.section.trim() !== "") return true;

  if (query.skillMin !== undefined && query.skillMin !== defaultAdvancedSearchQuery.skillMin) return true;
  if (query.skillMax !== undefined && query.skillMax !== defaultAdvancedSearchQuery.skillMax) return true;
  if (query.flowMin !== undefined && query.flowMin !== defaultAdvancedSearchQuery.flowMin) return true;
  if (query.flowMax !== undefined && query.flowMax !== defaultAdvancedSearchQuery.flowMax) return true;

  if (query.includeUnknownSkill !== undefined && query.includeUnknownSkill !== defaultAdvancedSearchQuery.includeUnknownSkill) return true;
  if (query.includeUnknownFlow !== undefined && query.includeUnknownFlow !== defaultAdvancedSearchQuery.includeUnknownFlow) return true;
  if (query.includeDams !== undefined && query.includeDams !== defaultAdvancedSearchQuery.includeDams) return true;

  return false;
}

function skillToNumber(skill: string | number): number {
  if (typeof skill === "number") return skill;
  const map: Record<string, number> = {
    FW: 1,
    B: 2,
    N: 3,
    LI: 4,
    I: 5,
    HI: 6,
    A: 7,
    E: 8,
  };
  return map[skill.toUpperCase()] || Infinity;
}

function getTagArray(tags: any): string[] {
  if (Array.isArray(tags)) return tags;
  if (tags) return [tags];
  return [];
}


function matchNormalSearch(r: RiverData, terms: string[]): boolean {
  if (terms.length === 0) return true;
  const searchStr = [
    r.name || "",
    r.section || "",
    ...getTagArray(r.tags),
    r.isGauge ? "gauge" : "",
    ...(r.gauges ? r.gauges.map(g => g.name || "").filter(Boolean) : [])
  ].join(" ").toLowerCase();


  return terms.every(term => searchStr.includes(term));
}

function matchExplicitMatch(r: RiverData, query: AdvancedSearchQuery): boolean {
  if (query.name && !String(r.name || "").toLowerCase().includes(query.name!.toLowerCase())) {
     return false;
  }
  if (query.section && !String(r.section || "").toLowerCase().includes(query.section!.toLowerCase())) {
     return false;
  }
  return true;
}

function matchSkill(r: RiverData, query: AdvancedSearchQuery): boolean {
  if (query.skillMin !== undefined && query.skillMax !== undefined) {
    const s = skillToNumber(r.skill || "");
    if (s === Infinity) return !!query.includeUnknownSkill;
    return s >= query.skillMin! && s <= query.skillMax!;
  }
  return true;
}

function matchFlow(r: RiverData, query: AdvancedSearchQuery): boolean {
  if (query.flowMin !== undefined && query.flowMax !== undefined) {
    if (r.dam && query.includeDams) return true;
    if (r.running === undefined) return !!query.includeUnknownFlow;
    return r.running >= query.flowMin! && r.running <= query.flowMax!;
  }
  return true;
}

function matchProximity(r: RiverData, query: AdvancedSearchQuery): boolean {
  if (query.distanceMax && query.userLat && query.userLon) {
    if (!r.accessPoints || r.accessPoints.length === 0) return false;
    const start = r.accessPoints[0];
    const rLat = start.lat;
    const rLon = start.lon;
    if (!rLat || !rLon) return false;

    const distanceMiles = lambert(query.userLat!, query.userLon!, rLat, rLon);
    return distanceMiles <= query.distanceMax!;
  }
  return true;
}

function getSortKey(r: RiverData, sortBy: string): any {
  switch (sortBy) {
    case "alphabetical": return String(r.name || "").toLowerCase();
    case "skill": return skillToNumber(r.skill || "");
    case "class": return r.class || "";
    case "running": return r.running ?? -1;
    case "state": return String(r.states || "").toLowerCase();
    default: return 0;
  }
}

function getSearchRelevanceScore(r: RiverData, terms: string[]): number {
  if (terms.length === 0) return 0;
  let score = 0;

  const name = String(r.name || "").toLowerCase();
  const section = String(r.section || "").toLowerCase();

  const tagsStr = [
    ...getTagArray(r.tags),
    r.isGauge ? "gauge" : "",
    ...(r.gauges ? r.gauges.map(g => g.name || "").filter(Boolean) : [])
  ].join(" ").toLowerCase();


  for (const term of terms) {
    const t = term.toLowerCase();
    const escapedTerm = t.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const prefixRegex = new RegExp(`(^|[^a-z0-9])${escapedTerm}`, 'i'); 

    if (name === t) {
      score += 100;
    } else if (name.startsWith(t)) {
      score += 80;
    } else if (prefixRegex.test(name)) {
      score += 60;
    } else if (name.includes(t)) {
      score += 30;
    } else if (section === t) {
      score += 50; 
    } else if (section.startsWith(t)) {
      score += 40;
    } else if (prefixRegex.test(section)) {
      score += 30;
    } else if (section.includes(t)) {
      score += 15;
    } else if (prefixRegex.test(tagsStr)) {
      score += 10;
    } else if (tagsStr.includes(t)) {
      score += 2;
    }
  }
  return score;
}

export function filterRivers(
  rivers: RiverData[],
  query: AdvancedSearchQuery,
): RiverData[] {
  let list = [...rivers];

  if (query.listData) {
    const validIds = new Set(query.listData.map(l => l.id));
    list = list.filter((r) => validIds.has(r.id));
  }

  const terms = query.normalSearch 
    ? query.normalSearch.toLowerCase().split(/[ ,]+/).filter(t => t.length > 0) 
    : [];

  list = list.filter((r) => {
    if (query.country && query.country !== "global") {
       const countries = getRiverCountries(r, query.stateToCountryMap);
       if (!countries.has(query.country as CountryCode)) return false;
    }
    if (!matchNormalSearch(r, terms)) return false;
    if (!matchExplicitMatch(r, query)) return false;
    if (!matchSkill(r, query)) return false;
    if (!matchFlow(r, query)) return false;
    if (!matchProximity(r, query)) return false;
    return true;
  });

  // Sorting
  if (query.sortBy && query.sortBy !== "none") {
    const isAlphabetical = query.sortBy === "alphabetical";
    const mapped = list.map((r, i) => ({ 
        index: i, 
        value: r, 
        sortKey: getSortKey(r, query.sortBy!),
    }));

    mapped.sort((a, b) => {
      // Gauge separation ONLY for alphabetical sort
      if (isAlphabetical && terms.indexOf("gauge") === -1) {
        const aGauge = !!a.value.isGauge;
        const bGauge = !!b.value.isGauge;
        if (!aGauge && bGauge) return -1;
        if (aGauge && !bGauge) return 1;
      }

      // Respect search relevance for alphabetical sort if search terms exist
      if (isAlphabetical && terms.length > 0) {
        const aScore = getSearchRelevanceScore(a.value, terms);
        const bScore = getSearchRelevanceScore(b.value, terms);
        if (aScore !== bScore) {
          return bScore - aScore;
        }
      }

      let cmp = 0;
      if (a.sortKey > b.sortKey) cmp = 1;
      else if (a.sortKey < b.sortKey) cmp = -1;

      if (cmp !== 0) {
        return query.sortReverse ? -cmp : cmp;
      }

      return a.index - b.index;
    });

    list = mapped.map(m => m.value);

  } else if (query.listData && query.listData.length > 0) {
    // If no explicit sort is chosen but we have list constraints, sort by the implicit List Order!
    const orderMap = new Map(query.listData.map((ld) => [ld.id, ld.order]));
    const mapped = list.map((r, i) => ({ index: i, value: r, sortKey: orderMap.get(r.id) ?? Infinity }));

    mapped.sort((a, b) => {
      return a.sortKey - b.sortKey;
    });

    list = mapped.map(m => m.value);
  } else {
    // If no explicit sort and no list constraint, sort rivers above gauges
    // Prioritize full word matches in search
    const mapped = list.map((r, i) => ({ 
      index: i, 
      value: r,
      score: getSearchRelevanceScore(r, terms)
    }));
    mapped.sort((a, b) => {
      const aGauge = !!a.value.isGauge;
      const bGauge = !!b.value.isGauge;

      // 1. Strictly Rivers above Gauges (ONLY IF "gauge" is NOT in search terms)
      if (terms.indexOf("gauge") === -1) {
        if (!aGauge && bGauge) return -1;
        if (aGauge && !bGauge) return 1;
      }

      // 2. Sort by search relevance
      if (a.score !== b.score) {
        return b.score - a.score;
      }

      // 3. Tiebreaker: Rivers above Gauges (Fallthrough)
      if (!aGauge && bGauge) return -1;
      if (aGauge && !bGauge) return 1;

      // 4. Preserve original order
      return a.index - b.index; // Preserve original order
    });
    list = mapped.map(m => m.value);
  }

  return list;
}

import type { RiverData } from "../types/River";

// Used for converting flow values logarithmically between thresholds
function logDist(low: number, high: number, ratio: number = 0.5): number {
  let lowLog = Math.log10(low);
  let highLog = Math.log10(high);
  if (lowLog > highLog) {
    const temp = lowLog;
    lowLog = highLog;
    highLog = temp;
  }
  return Math.pow(10, lowLog + (highLog - lowLog) * ratio);
}

function calculateArrayPosition(
  arr: (number | undefined)[],
  pos: number,
): number | undefined {
  const negativeOptions: number[] = [];
  const positiveOptions: number[] = [];

  arr.forEach((value, index) => {
    if (value !== undefined) {
      const optionNum = index - pos;
      if (optionNum > 0) positiveOptions.push(index);
      if (optionNum < 0) negativeOptions.push(index);
    }
  });

  positiveOptions.sort((a, b) => a - b);
  negativeOptions.sort((a, b) => b - a);

  let bottomPos = negativeOptions.length > 0 ? negativeOptions[0] : undefined;
  let topPos = positiveOptions.length > 0 ? positiveOptions[0] : undefined;

  if (bottomPos === undefined) bottomPos = positiveOptions.length > 1 ? positiveOptions[1] : undefined;
  if (topPos === undefined) topPos = negativeOptions.length > 1 ? negativeOptions[1] : undefined;

  if (topPos === undefined || bottomPos === undefined) return undefined;

  const denominator = Math.abs(topPos - bottomPos);
  if (denominator === 0) return arr[topPos]!;

  const numerator = pos - Math.min(bottomPos, topPos);

  return logDist(arr[topPos]!, arr[bottomPos]!, numerator / denominator);
}

// Helper to dynamically calculate descending array configurations
function calculateParsedThresholds(thresholds: (any)[]): (number | undefined)[] {
  let parsedValues: (number | undefined)[] = thresholds.map(() => undefined);
  let currentMax: number | undefined;

  for (let i = 0; i < thresholds.length; i++) {
    const rawValue = thresholds[i];
    const value = (rawValue !== undefined && rawValue !== null && rawValue !== "") ? Number(rawValue) : undefined;
    if (value !== undefined && !isNaN(value)) {
      if (currentMax !== undefined && value < currentMax) continue; 
      parsedValues[i] = currentMax = value;
    }
  }

  // Interplate missing logarithmic zones based off surrounding metrics cleanly
  parsedValues = parsedValues.map((val, index) =>
    val !== undefined ? val : calculateArrayPosition(parsedValues, index),
  );

  return parsedValues;
}

export function calculateRelativeFlow(river: RiverData): number | null {
  if (!river.flow || !river.flow.unit) return null;

  let flowLevel: number | undefined;
  if (river.flow.unit === "cfs") flowLevel = river.latestReading ?? river.cfs;
  else if (river.flow.unit === "ft") flowLevel = river.latestReading ?? river.ft;
  else if (river.flow.unit === "m") flowLevel = river.latestReading ?? river.m;
  else if (river.flow.unit === "cms") flowLevel = river.latestReading ?? river.cms;

  if (flowLevel === undefined || isNaN(flowLevel)) return null;

  const thresholds = [
    river.flow.min,
    river.flow.low,
    river.flow.mid,
    river.flow.high,
    river.flow.max
  ];

  const parsedValues = calculateParsedThresholds(thresholds);
  const [minrun, lowflow, midflow, highflow, maxrun] = parsedValues;

  const calculateRatio = (low: number, high: number, current: number) => {
    return (
      (Math.log(current) - Math.log(low)) / (Math.log(high) - Math.log(low))
    );
  };

  if (minrun !== undefined && flowLevel <= minrun) return 0;
  if (maxrun !== undefined && flowLevel >= maxrun) return 4;

  if (minrun !== undefined && lowflow !== undefined && flowLevel < lowflow) {
    return calculateRatio(minrun, lowflow, flowLevel);
  }
  if (lowflow !== undefined && midflow !== undefined && flowLevel < midflow) {
    return 1 + calculateRatio(lowflow, midflow, flowLevel);
  }
  if (midflow !== undefined && highflow !== undefined && flowLevel < highflow) {
    return 2 + calculateRatio(midflow, highflow, flowLevel);
  }
  if (highflow !== undefined && maxrun !== undefined && flowLevel < maxrun) {
    return 3 + calculateRatio(highflow, maxrun, flowLevel);
  }

  return null;
}

export function calculateColor(
  running: number | null,
  isDarkMode = false,
  isColorBlind = false,
): string {
  if (running === null) return "";

  if (isColorBlind) {
    let orange, blue;
    if (isDarkMode) {
      orange = [112, 56, 0];
      blue = [0, 0, 112];
    } else {
      orange = [255, 189, 122];
      blue = [153, 153, 255];
    }
    const res = orange.map((o, index) => {
      const b = blue[index];
      return (o * (4 - running) + b * running) / 4;
    });
    return `rgb(${res.join(",")})`;
  } else {
    let lightness = isDarkMode ? 22 : 70;
    if (!isDarkMode) {
      if (running > 3) lightness += 10 * (running - 3);
      else if (running < 1) lightness += 4 * (1 - running);
    }
    return `hsl(${0 + 60 * running},100%,${lightness}%)`;
  }
}

// Map tile calculation based on standard OSM Slippy Math (EPSG:3857)

export interface BoundingBox {
    minLat: number;
    maxLat: number;
    minLon: number;
    maxLon: number;
}

// World Bounds
export const WORLD_BOUNDS: BoundingBox = {
    minLat: -85.0511,
    maxLat: 85.0511,
    minLon: -180,
    maxLon: 180
};

// North America Bounds (Roughly captures Alaska + Hawaii + Lower 48 + Canada)
export const NORTH_AMERICA_BOUNDS: BoundingBox = {
    minLat: 15.0,
    maxLat: 72.0,
    minLon: -170.0,
    maxLon: -50.0
};

const DEG_TO_RAD = Math.PI / 180;

export const lon2tile = (lon: number, zoom: number): number => {
    return Math.floor(((lon + 180) / 360) * Math.pow(2, zoom));
};

export const lat2tile = (lat: number, zoom: number): number => {
    const latRad = lat * DEG_TO_RAD;
    return Math.floor(
        ((1 -
            Math.log(
                Math.tan(latRad) + 1 / Math.cos(latRad)
            ) /
                Math.PI) /
            2) *
            Math.pow(2, zoom)
    );
};

export const generateTileQueue = (
    bounds: BoundingBox,
    minZoom: number,
    maxZoom: number
): string[] => {
    const urls: string[] = [];

    for (let z = minZoom; z <= maxZoom; z++) {
        // Find grid boundaries for this zoom
        const minX = Math.max(0, lon2tile(bounds.minLon, z));
        const maxX = Math.min(Math.pow(2, z) - 1, lon2tile(bounds.maxLon, z));

        // Note: latitude goes from + (North) to - (South) in coordinates,
        // but Y tiles go from 0 (North/Top) to max (South/Bottom).
        const minY = Math.max(0, lat2tile(bounds.maxLat, z));
        const maxY = Math.min(Math.pow(2, z) - 1, lat2tile(bounds.minLat, z));

        for (let x = minX; x <= maxX; x++) {
            for (let y = minY; y <= maxY; y++) {
                urls.push(`https://tile.openstreetmap.org/${z}/${x}/${y}.png`);
            }
        }
    }

    return urls;
};

export const downloadMapTiles = async (
    urls: string[],
    onProgress: (done: number, total: number) => void
) => {
    const total = urls.length;
    let done = 0;

    // Process in batches of 10 to avoid suffocating the browser's HTTP queue
    const BATCH_SIZE = 10;
    const cache = await caches.open('offline-map-tiles');

    for (let i = 0; i < urls.length; i += BATCH_SIZE) {
        const batch = urls.slice(i, i + BATCH_SIZE);

        await Promise.all(
            batch.map(async (url) => {
                try {
                    // Skip if already cached, preventing network abuse on boots
                    const existing = await cache.match(url);
                    if (existing) return;

                    // Fetch natively and pump explicitly into the sw-cache bucket
                    const res = await fetch(url, { mode: "cors" });
                    if (res.ok) {
                        await cache.put(url, res);
                    }
                } catch (e: unknown) {
                    if (e instanceof Error) console.warn("Failed to fetch map tile:", url, e.message);
                }
            })
        );

        done += batch.length;
        if (done > total) done = total; // clamp for safety
        onProgress(done, total);

        // Let the JS event loop breathe so the UI doesn't freeze
        await new Promise(resolve => setTimeout(resolve, 10));
    }
};

export const getCacheUsageString = async (): Promise<string> => {
    try {
        let tileCount = 0;
        try {
            const cache = await caches.open('offline-map-tiles');
            const keys = await cache.keys();
            tileCount = keys.length;
        } catch {
            // ignore
        }

        if (tileCount > 0) {
            // Rough average of 15KB per slippy map PNG
            const estimatedMb = ((tileCount * 15) / 1024).toFixed(1);
            return `${tileCount.toLocaleString()} Tiles Offline (~${estimatedMb} MB)`;
        }

        // Fallback to native hardware if 0 bounds
        if ('storage' in navigator && 'estimate' in navigator.storage) {
            const estimate = await navigator.storage.estimate();
            if (estimate.usage !== undefined && estimate.usage > 0) {
                const usageMB = (estimate.usage / (1024 * 1024)).toFixed(1);
                return `0 Tiles Cached (${usageMB} MB System Overhead)`;
            }
        }

        return '0 Tiles Cached';
    } catch {
        return 'Storage error';
    }
};

export const autoDownloadBaseMaps = async () => {
    try {
        const worldUrls = generateTileQueue(WORLD_BOUNDS, 0, 2);
        const usUrls = generateTileQueue(NORTH_AMERICA_BOUNDS, 0, 4);

        // Let it run silently in the background
        await downloadMapTiles([...worldUrls, ...usUrls], () => {});
    } catch (err: unknown) {
        if (err instanceof Error) console.error("Auto base map download failed", err.message);
    }
};

/**
 * Heuristically detects the maximum zoom level currently downloaded 
 * for a specific region by scanning cache keys.
 */
export const detectMaxZoom = async (type: 'world' | 'na'): Promise<number> => {
    try {
        const cache = await caches.open('offline-map-tiles');
        const keys = await cache.keys();
        const urls = keys.map(k => k.url);

        const bounds = type === 'world' ? WORLD_BOUNDS : NORTH_AMERICA_BOUNDS;
        const tileCountsByZoom: Record<number, number> = {};
        const zoomRegex = /\/(\d+)\/(\d+)\/(\d+)\.png$/;

        const boundsCache: Record<number, { minX: number, maxX: number, minY: number, maxY: number }> = {};

        function isTileInBounds(x: number, y: number, z: number, bounds: BoundingBox) {
            if (!boundsCache[z]) {
                boundsCache[z] = {
                    minX: Math.max(0, lon2tile(bounds.minLon, z)),
                    maxX: Math.min(Math.pow(2, z) - 1, lon2tile(bounds.maxLon, z)),
                    minY: Math.max(0, lat2tile(bounds.maxLat, z)),
                    maxY: Math.min(Math.pow(2, z) - 1, lat2tile(bounds.minLat, z))
                };
            }
            const b = boundsCache[z];
            return (x >= b.minX && x <= b.maxX && y >= b.minY && y <= b.maxY);
        }

        // Group and count strictly within geographic target bounds
        for (const url of urls) {
            const match = zoomRegex.exec(url);
            if (match) {
                const z = parseInt(match[1], 10);
                const x = parseInt(match[2], 10);
                const y = parseInt(match[3], 10);

                if (isTileInBounds(x, y, z, bounds)) {
                    tileCountsByZoom[z] = (tileCountsByZoom[z] || 0) + 1;
                }
            }
        }

        let maxCompleteZoom = -1;
        const maxPossible = type === 'world' ? 10 : 14;

        // Validate each level sequentially. Break cleanly if a layer is missing tiles.
        for (let z = 0; z <= maxPossible; z++) {
            const minX = Math.max(0, lon2tile(bounds.minLon, z));
            const maxX = Math.min(Math.pow(2, z) - 1, lon2tile(bounds.maxLon, z));
            const minY = Math.max(0, lat2tile(bounds.maxLat, z));
            const maxY = Math.min(Math.pow(2, z) - 1, lat2tile(bounds.minLat, z));

            const expectedCount = (maxX - minX + 1) * (maxY - minY + 1);
            const actualCount = tileCountsByZoom[z] || 0;

            if (actualCount >= expectedCount) {
                maxCompleteZoom = z;
            } else {
                break; 
            }
        }

        // Return standard minimum baselines natively 
        const defaultZoom = type === 'world' ? 2 : 4;
        return maxCompleteZoom >= defaultZoom ? maxCompleteZoom : defaultZoom;
    } catch {
        return type === 'world' ? 2 : 4;
    }
};

/**
 * ⚠️ IMPORTANT: Cross-Environment Synchronization ⚠️
 * This validation logic is identically mirrored between the frontend and backend.
 * If you update this file, you MUST identically update its mirror:
 * Backend Mirror: functions/src/services/riverValidation.ts
 */

export interface RiverValidationResult {
  isValid: boolean;
  errors: string[];
  warnings: string[];
}

export function validateRiver(river: any): RiverValidationResult {
  const errors: string[] = [];
  const warnings: string[] = [];

  if (!river) {
    return { isValid: false, errors: ["River object is completely null or undefined."], warnings: [] };
  }

  if (!river.id || typeof river.id !== "string" || river.id.trim() === "") {
    errors.push("Missing or invalid River ID.");
  }

  if (!river.name || typeof river.name !== "string" || river.name.trim() === "") {
    errors.push("Missing or invalid River Name.");
  }

  if ((river.writeup || "").match(/<img[^>]+src=["']data:image/i)) {
    errors.push("Raw image structures (base64) are strictly disallowed to maintain fast load times and database space.");
  }

  const VALID_SKILLS = new Set(["?", "fw", "b", "n", "n+", "li-", "li", "li+", "i-", "i", "i+", "hi-", "hi", "hi+", "a-", "a", "a+", "e-", "e", "e+"]);

  if (river.skill !== undefined && river.skill !== null) {
      if (typeof river.skill === "string") {
          if (!VALID_SKILLS.has(river.skill.trim().toLowerCase())) {
              errors.push(`Skill is invalid. Expected a recognized abbreviation like 'FW', 'B', 'N', etc. Got '${river.skill}'.`);
          }
      } else if (typeof river.skill === "number") {
          if (river.skill < 1 || river.skill > 8) {
              errors.push(`Skill index is out of range. Expected 1-8, got ${river.skill}.`);
          }
      } else {
          errors.push("Skill must be a string (abbreviation) or a number (index 1-8).");
      }
  }

  try {
    const jsonStr = JSON.stringify(river);
    const byteLength = new TextEncoder().encode(jsonStr).length;
    if (byteLength > 25000) {
      warnings.push(`This river profile is abnormally large (${(byteLength / 1024).toFixed(1)} kB). The standard recommended limit is ~25 kB maximum.`);
    }
  } catch {
    errors.push("Failed to serialize River data due to circular references or unsupported formats.");
  }

  if (river.tags && !Array.isArray(river.tags)) {
    errors.push("Tags must be an array of strings.");
  }

  const gauges = Array.isArray(river.gauges) ? river.gauges : [];
  if (river.gauges && !Array.isArray(river.gauges)) {
    errors.push("Gauges must be an array.");
  }

  const primaryCount = gauges.filter((g: any) => g.isPrimary).length;
  if (gauges.length > 0 && primaryCount > 1) {
    errors.push("At most ONE gauge can be marked as primary.");
  }

  if (river.accessPoints && !Array.isArray(river.accessPoints)) {
    errors.push("Access points must be an array.");
  }

  if (river.flow) {
    const tiers = [river.flow.min, river.flow.low, river.flow.mid, river.flow.high, river.flow.max];
    const validTiers = tiers.filter((t: any) => t !== null && t !== undefined && t !== "");

    if (validTiers.length > 0 && (!river.flow.unit || typeof river.flow.unit !== "string" || river.flow.unit.trim() === "")) {
      errors.push("Flow unit ('cfs', 'ft', 'cms', 'm') must be specified if any flow tier values are provided.");
    }

    if (primaryCount > 0) {
      for (let i = 0; i < validTiers.length - 1; i++) {
          if (Number(validTiers[i]) >= Number(validTiers[i+1])) {
              errors.push("Flow tiers (min, low, mid, high, max) must be in strictly ascending numeric order.");
              break;
          }
      }
    }
  }

  return {
    isValid: errors.length === 0,
    errors,
    warnings
  };
}

export function toDecimalDegrees(coordString: string | number | null | undefined): number | null {
    if (coordString === null || coordString === undefined || coordString === "") return null;
    if (typeof coordString === "number") return coordString;

    let str = coordString.trim().toUpperCase();

    // Check for N/S/E/W directions to apply negation
    let multiplier = 1;
    if (str.includes('S') || str.includes('W')) {
        multiplier = -1;
    }
    // Remove direction letters completely now
    str = str.replace(/[NSEW]/g, "").trim();

    // If it's a simple decimal number just parse it
    if (/^-?[\d.]+$/.test(str)) {
         const num = parseFloat(str) * (multiplier === -1 && !str.startsWith('-') ? -1 : 1);
         return isNaN(num) ? null : num;
    }

    // Try parsing degrees, minutes, seconds using regex
    // Formats: 38° 50' 11.2" | 38 50 11.2 | 38 50.12
    // eslint-disable-next-line sonarjs/regex-complexity, no-useless-escape
    const regex = /^\s*(-?\d+)[^\d\.]+(\d+(?:\.\d+)?)(?:[^\d\.]+(\d+(?:\.\d+)?))?[^\d]*$/;
    // eslint-disable-next-line sonarjs/prefer-regexp-exec
    const match = str.match(regex);

    if (match) {
        let degrees = parseFloat(match[1]);
        const isNegative = degrees < 0;
        degrees = Math.abs(degrees);

        const minutes = match[2] ? parseFloat(match[2]) : 0;
        const seconds = match[3] ? parseFloat(match[3]) : 0;

        let decimal = degrees + (minutes / 60) + (seconds / 3600);
        if (isNegative) decimal = -decimal;

        decimal = decimal * multiplier;
        return decimal;
    }

    // Fallback naive parse
    const naive = parseFloat(str);
    if (!isNaN(naive)) return naive * (multiplier === -1 && String(naive)[0] !== '-' ? -1 : 1);

    return null;
}
